1: const std = @import("std");
2: const assert = std.debug.assert;
3: const math = std.math;
4: const mem = std.mem;
5: const stdx = @import("stdx");
6: const div_ceil = stdx.div_ceil;
7: const disjoint_slices = stdx.disjoint_slices;
8: const maybe = stdx.maybe;
9: 
10: const constants = @import("constants.zig");
11: 
12: /// Encode or decode a bitset using Daniel Lemire's EWAH codec.
13: /// ("Histogram-Aware Sorting for Enhanced Word-Aligned Compression in Bitmap Indexes")
14: ///
15: /// EWAH uses only two types of words, where the first type is a 64-bit verbatim ("literal") word.
16: /// The second type of word is a marker word:
17: /// * The first bit indicates which uniform word will follow.
18: /// * The next 31 bits are used to store the number of uniform words.
19: /// * The last 32 bits are used to store the number of literal words following the uniform words.
20: /// EWAH bitmaps begin with a marker word. A 'marker' looks like (assuming a 64-bit word):
21: ///
22: ///     [uniform_bit:u1][uniform_word_count:u31(LE)][literal_word_count:u32(LE)]
23: ///
24: /// and is immediately followed by `literal_word_count` 64-bit literals.
25: /// When decoding a marker, the uniform words precede the literal words.
26: ///
27: /// This encoding requires that the architecture is little-endian with 64-bit words.
28: pub fn ewah(comptime Word: type) type {
29:     const word_bits = @bitSizeOf(Word);
30: 
31:     return struct {
32:         const marker_uniform_word_count_max = (1 << ((word_bits / 2) - 1)) - 1;
33:         const marker_literal_word_count_max = (1 << (word_bits / 2)) - 1;
34: 
35:         pub const MarkerUniformCount = std.meta.Int(.unsigned, word_bits / 2 - 1); // Word=u64 → u31
36:         pub const MarkerLiteralCount = std.meta.Int(.unsigned, word_bits / 2); // Word=u64 → u32
37: 
38:         pub const Marker = packed struct(Word) {
39:             // Whether the uniform word is all 0s or all 1s.
40:             uniform_bit: u1,
41:             // 31-bit number of uniform words following the marker.
42:             uniform_word_count: MarkerUniformCount,
43:             // 32-bit number of literal words following the uniform words.
44:             literal_word_count: MarkerLiteralCount,
45:         };
46: 
47:         comptime {
48:             assert(@import("builtin").target.cpu.arch.endian() == std.builtin.Endian.little);
49:             assert(@typeInfo(Word).int.signedness == .unsigned);
50:             assert(word_bits % 8 == 0); // A multiple of a byte, so that words can be cast to bytes.
51:             assert(@bitSizeOf(Marker) == word_bits);
52:             assert(@sizeOf(Marker) == @sizeOf(Word));
53: 
54:             assert(@bitSizeOf(MarkerUniformCount) % 2 == 1);
55:             assert(math.maxInt(MarkerUniformCount) == marker_uniform_word_count_max);
56: 
57:             assert(@bitSizeOf(MarkerLiteralCount) % 2 == 0);
58:             assert(math.maxInt(MarkerLiteralCount) == marker_literal_word_count_max);
59:         }
60: 
61:         inline fn marker_word(mark: Marker) Word {
62:             return @bitCast(mark);
63:         }
64: 
65:         pub const Decoder = struct {
66:             /// The number of bytes of the source buffer (the encoded data) that still need to be
67:             /// processed.
68:             source_size_remaining: usize,
69:             target_words: []Word,
70:             target_index: usize = 0,
71:             source_literal_words: usize = 0,
72: 
73:             /// Returns the number of *words* written to `target_words` by this invocation.
74:             // TODO Refactor to return an error when `source_chunk` is invalid,
75:             // so that we can test invalid encodings.
76:             pub fn decode_chunk(
77:                 decoder: *Decoder,
78:                 source_chunk: []align(@alignOf(Word)) const u8,
79:             ) usize {
80:                 assert(source_chunk.len % @sizeOf(Word) == 0);
81: 
82:                 decoder.source_size_remaining -= source_chunk.len;
83: 
84:                 const source_words = mem.bytesAsSlice(Word, source_chunk);
85:                 const target_words = decoder.target_words;
86:                 assert(disjoint_slices(u8, Word, source_chunk, target_words));
87: 
88:                 var source_index: usize = 0;
89:                 var target_index: usize = decoder.target_index;
90:                 defer decoder.target_index = target_index;
91: 
92:                 if (decoder.source_literal_words > 0) {
93:                     const literal_word_count_chunk =
94:                         @min(decoder.source_literal_words, source_words.len);
95: 
96:                     stdx.copy_disjoint(
97:                         .exact,
98:                         Word,
99:                         target_words[target_index..][0..literal_word_count_chunk],
100:                         source_words[source_index..][0..literal_word_count_chunk],
101:                     );
102:                     source_index += literal_word_count_chunk;
103:                     target_index += literal_word_count_chunk;
104:                     decoder.source_literal_words -= literal_word_count_chunk;
105:                 }
106: 
107:                 while (source_index < source_words.len) {
108:                     assert(decoder.source_literal_words == 0);
109: 
110:                     const marker: *const Marker = @ptrCast(&source_words[source_index]);
111:                     source_index += 1;
112:                     @memset(
113:                         target_words[target_index..][0..marker.uniform_word_count],
114:                         if (marker.uniform_bit == 1) ~@as(Word, 0) else 0,
115:                     );
116:                     target_index += marker.uniform_word_count;
117: 
118:                     const literal_word_count_chunk =
119:                         @min(marker.literal_word_count, source_words.len - source_index);
120:                     stdx.copy_disjoint(
121:                         .exact,
122:                         Word,
123:                         target_words[target_index..][0..literal_word_count_chunk],
124:                         source_words[source_index..][0..literal_word_count_chunk],
125:                     );
126:                     source_index += literal_word_count_chunk;
127:                     target_index += literal_word_count_chunk;
128:                     decoder.source_literal_words =
129:                         marker.literal_word_count - literal_word_count_chunk;
130:                 }
131:                 assert(source_index <= source_words.len);
132:                 assert(target_index <= target_words.len);
133: 
134:                 return target_index - decoder.target_index;
135:             }
136: 
137:             pub fn done(decoder: *const Decoder) bool {
138:                 assert(decoder.target_index <= decoder.target_words.len);
139: 
140:                 if (decoder.source_size_remaining == 0) {
141:                     assert(decoder.source_literal_words == 0);
142:                     return true;
143:                 } else {
144:                     maybe(decoder.source_literal_words == 0);
145:                     return false;
146:                 }
147:             }
148:         };
149: 
150:         pub fn decode_chunks(target_words: []Word, source_size: usize) Decoder {
151:             return .{
152:                 .target_words = target_words,
153:                 .source_size_remaining = source_size,
154:             };
155:         }
156: 
157:         // (This is a helper for testing only.)
158:         /// Decodes the compressed bitset in `source` into `target_words`.
159:         /// Returns the number of *words* written to `target_words`.
160:         pub fn decode_all(source: []align(@alignOf(Word)) const u8, target_words: []Word) usize {
161:             comptime assert(constants.verify);
162:             assert(source.len % @sizeOf(Word) == 0);
163:             assert(disjoint_slices(u8, Word, source, target_words));
164: 
165:             var decoder = decode_chunks(target_words, source.len);
166:             return decoder.decode_chunk(source);
167:         }
168: 
169:         pub const Encoder = struct {
170:             source_words: []const Word,
171:             source_index: usize = 0,
172:             /// The number of literals left over from the previous encode() call that still need to
173:             /// be copied.
174:             literal_word_count: usize = 0,
175: 
176:             trailing_zero_runs_count: usize = 0,
177: 
178:             /// Returns the number of bytes written to `target_chunk` by this invocation.
179:             pub fn encode_chunk(encoder: *Encoder, target_chunk: []align(@alignOf(Word)) u8) usize {
180:                 const source_words = encoder.source_words;
181:                 assert(disjoint_slices(Word, u8, source_words, target_chunk));
182:                 assert(encoder.source_index <= encoder.source_words.len);
183:                 assert(encoder.literal_word_count <= encoder.source_words.len);
184: 
185:                 const target_words = mem.bytesAsSlice(Word, target_chunk);
186:                 @memset(target_words, 0);
187: 
188:                 var target_index: usize = 0;
189:                 var source_index: usize = encoder.source_index;
190: 
191:                 if (encoder.literal_word_count > 0) {
192:                     maybe(encoder.source_index == 0);
193: 
194:                     const literal_word_count_chunk =
195:                         @min(encoder.literal_word_count, target_words.len);
196: 
197:                     stdx.copy_disjoint(
198:                         .exact,
199:                         Word,
200:                         target_words[target_index..][0..literal_word_count_chunk],
201:                         source_words[source_index..][0..literal_word_count_chunk],
202:                     );
203: 
204:                     source_index += literal_word_count_chunk;
205:                     target_index += literal_word_count_chunk;
206:                     encoder.literal_word_count -= literal_word_count_chunk;
207:                 }
208: 
209:                 while (source_index < source_words.len and target_index < target_words.len) {
210:                     assert(encoder.literal_word_count == 0);
211: 
212:                     const word = source_words[source_index];
213: 
214:                     const uniform_word_count = count: {
215:                         if (is_literal(word)) break :count 0;
216:                         // Measure run length.
217:                         const uniform_max = @min(
218:                             source_words.len - source_index,
219:                             marker_uniform_word_count_max,
220:                         );
221:                         for (source_words[source_index..][0..uniform_max], 0..) |w, i| {
222:                             if (w != word) break :count i;
223:                         }
224:                         break :count uniform_max;
225:                     };
226:                     source_index += uniform_word_count;
227:                     // For consistent encoding, set the run/uniform bit to 0 when there is no run.
228:                     const uniform_bit: u1 =
229:                         if (uniform_word_count == 0) 0 else @intCast(word & 1);
230: 
231:                     const literal_word_count = count: {
232:                         // Count sequential literals that immediately follow the run.
233:                         const literals_max = @min(
234:                             source_words.len - source_index,
235:                             marker_literal_word_count_max,
236:                         );
237:                         for (source_words[source_index..][0..literals_max], 0..) |w, i| {
238:                             if (!is_literal(w)) break :count i;
239:                         }
240:                         break :count literals_max;
241:                     };
242: 
243:                     target_words[target_index] = marker_word(.{
244:                         .uniform_bit = uniform_bit,
245:                         .uniform_word_count = @intCast(uniform_word_count),
246:                         .literal_word_count = @intCast(literal_word_count),
247:                     });
248:                     target_index += 1;
249: 
250:                     const literal_word_count_chunk =
251:                         @min(literal_word_count, target_words.len - target_index);
252:                     stdx.copy_disjoint(
253:                         .exact,
254:                         Word,
255:                         target_words[target_index..][0..literal_word_count_chunk],
256:                         source_words[source_index..][0..literal_word_count_chunk],
257:                     );
258:                     source_index += literal_word_count_chunk;
259:                     target_index += literal_word_count_chunk;
260: 
261:                     encoder.literal_word_count = literal_word_count - literal_word_count_chunk;
262: 
263:                     if (uniform_bit == 0 and literal_word_count == 0) {
264:                         assert(uniform_word_count > 0);
265:                         encoder.trailing_zero_runs_count += 1;
266:                     } else {
267:                         encoder.trailing_zero_runs_count = 0;
268:                     }
269:                 }
270:                 assert(source_index <= source_words.len);
271: 
272:                 encoder.source_index = source_index;
273:                 return target_index * @sizeOf(Word);
274:             }
275: 
276:             pub fn done(encoder: *const Encoder) bool {
277:                 assert(encoder.source_index <= encoder.source_words.len);
278:                 return encoder.source_index == encoder.source_words.len;
279:             }
280:         };
281: 
282:         pub fn encode_chunks(source_words: []const Word) Encoder {
283:             return .{ .source_words = source_words };
284:         }
285: 
286:         // (This is a helper for testing only.)
287:         // Returns the number of bytes written to `target`.
288:         pub fn encode_all(source_words: []const Word, target: []align(@alignOf(Word)) u8) usize {
289:             comptime assert(constants.verify);
290:             assert(target.len == encode_size_max(source_words.len));
291:             assert(disjoint_slices(Word, u8, source_words, target));
292: 
293:             var encoder = encode_chunks(source_words);
294:             defer assert(encoder.done());
295: 
296:             return encoder.encode_chunk(target);
297:         }
298: 
299:         /// Returns the maximum number of bytes required to encode `word_count` words.
300:         /// Assumes (pessimistically) that every word will be encoded as a literal.
301:         pub fn encode_size_max(word_count: usize) usize {
302:             const marker_count = div_ceil(word_count, marker_literal_word_count_max);
303:             return marker_count * @sizeOf(Marker) + word_count * @sizeOf(Word);
304:         }
305: 
306:         inline fn is_literal(word: Word) bool {
307:             return word != 0 and word != ~@as(Word, 0);
308:         }
309:     };
310: }
311: 
312: test "ewah encode→decode cycle" {
313:     const fuzz = @import("./ewah_fuzz.zig");
314:     var prng = stdx.PRNG.from_seed_testing();
315: 
316:     inline for (.{ u8, u16, u32, u64, usize }) |Word| {
317:         const Context = fuzz.ContextType(Word);
318:         for ([_]usize{ 1, 2, 4, 5, 8, 16, 17, 32 }) |chunk_count| {
319:             var decoded: [4096]Word = undefined;
320:             const fuzz_options: Context.TestOptions = .{
321:                 .encode_chunk_words_count = @divFloor(decoded.len, chunk_count),
322:                 .decode_chunk_words_count = @divFloor(decoded.len, chunk_count),
323:             };
324: 
325:             @memset(&decoded, 0);
326:             try fuzz.fuzz_encode_decode(Word, std.testing.allocator, &decoded, fuzz_options);
327: 
328:             @memset(&decoded, std.math.maxInt(Word));
329:             try fuzz.fuzz_encode_decode(Word, std.testing.allocator, &decoded, fuzz_options);
330: 
331:             prng.fill(std.mem.asBytes(&decoded));
332:             try fuzz.fuzz_encode_decode(Word, std.testing.allocator, &decoded, fuzz_options);
333:         }
334:     }
335: }
336: 
337: test "ewah Word=u8" {
338:     try test_decode_with_word(u8);
339: 
340:     const codec = ewah(u8);
341:     for (0..math.maxInt(codec.MarkerUniformCount) + 1) |uniform_word_count| {
342:         try test_decode(u8, &.{
343:             codec.marker_word(.{
344:                 .uniform_bit = 0,
345:                 .uniform_word_count = @intCast(uniform_word_count),
346:                 .literal_word_count = 3,
347:             }),
348:             12,
349:             34,
350:             56,
351:         });
352:     }
353: 
354:     try std.testing.expectEqual(codec.encode_size_max(0), 0);
355:     try std.testing.expectEqual(codec.encode_all(&.{}, &.{}), 0);
356: }
357: 
358: test "ewah Word=u16" {
359:     try test_decode_with_word(u16);
360: }
361: 
362: // decode → encode → decode
363: fn test_decode_with_word(comptime Word: type) !void {
364:     const codec = ewah(Word);
365: 
366:     // No set bits.
367:     try test_decode(Word, &.{});
368:     // Alternating runs, no literals.
369:     try test_decode(Word, &.{
370:         codec.marker_word(.{ .uniform_bit = 0, .uniform_word_count = 2, .literal_word_count = 0 }),
371:         codec.marker_word(.{ .uniform_bit = 1, .uniform_word_count = 3, .literal_word_count = 0 }),
372:         codec.marker_word(.{ .uniform_bit = 0, .uniform_word_count = 4, .literal_word_count = 0 }),
373:     });
374:     // Alternating runs, with literals.
375:     try test_decode(Word, &.{
376:         codec.marker_word(.{ .uniform_bit = 0, .uniform_word_count = 2, .literal_word_count = 1 }),
377:         12,
378:         codec.marker_word(.{ .uniform_bit = 1, .uniform_word_count = 3, .literal_word_count = 1 }),
379:         34,
380:         codec.marker_word(.{ .uniform_bit = 0, .uniform_word_count = 4, .literal_word_count = 1 }),
381:         56,
382:     });
383:     // Consecutive run marker overflow.
384:     try test_decode(Word, &.{
385:         codec.marker_word(.{
386:             .uniform_bit = 0,
387:             .uniform_word_count = math.maxInt(codec.MarkerUniformCount),
388:             .literal_word_count = 0,
389:         }),
390:         codec.marker_word(.{ .uniform_bit = 0, .uniform_word_count = 2, .literal_word_count = 0 }),
391:     });
392: 
393:     var encoding = std.ArrayList(Word).init(std.testing.allocator);
394:     defer encoding.deinit();
395: 
396:     {
397:         // Consecutive literal marker overflow.
398:         try encoding.append(codec.marker_word(.{
399:             .uniform_bit = 0,
400:             .uniform_word_count = 0,
401:             .literal_word_count = math.maxInt(codec.MarkerLiteralCount),
402:         }));
403:         var i: Word = 0;
404:         while (i < math.maxInt(codec.MarkerLiteralCount)) : (i += 1) try encoding.append(i + 1);
405:         try encoding.append(codec.marker_word(.{
406:             .uniform_bit = 0,
407:             .uniform_word_count = 0,
408:             .literal_word_count = 2,
409:         }));
410:         try encoding.append(i + 2);
411:         try encoding.append(i + 3);
412:         try test_decode(Word, encoding.items);
413:         encoding.items.len = 0;
414:     }
415: }
416: 
417: fn test_decode(comptime Word: type, encoded_expect_words: []const Word) !void {
418:     const encoded_expect = mem.sliceAsBytes(encoded_expect_words);
419:     const codec = ewah(Word);
420:     const decoded_expect_data = try std.testing.allocator.alloc(Word, 4 * math.maxInt(Word));
421:     defer std.testing.allocator.free(decoded_expect_data);
422: 
423:     const decoded_expect_length = codec.decode_all(encoded_expect, decoded_expect_data);
424:     const decoded_expect = decoded_expect_data[0..decoded_expect_length];
425:     const encoded_actual = try std.testing.allocator.alignedAlloc(
426:         u8,
427:         @alignOf(Word),
428:         codec.encode_size_max(decoded_expect.len),
429:     );
430:     defer std.testing.allocator.free(encoded_actual);
431: 
432:     const encoded_actual_length = codec.encode_all(decoded_expect, encoded_actual);
433:     try std.testing.expectEqual(encoded_expect.len, encoded_actual_length);
434:     try std.testing.expectEqualSlices(u8, encoded_expect, encoded_actual[0..encoded_actual_length]);
435: 
436:     const encoded_size_max = codec.encode_size_max(decoded_expect.len);
