7: /// An intrusive doubly-linked list.
8: /// Currently it is LIFO for simplicity because its consumer (IO.awaiting) doesn't care about order.
9: pub fn DoublyLinkedListType(
10:     comptime Node: type,
11:     comptime field_back_enum: std.meta.FieldEnum(Node),
12:     comptime field_next_enum: std.meta.FieldEnum(Node),
13: ) type {
14:     assert(@typeInfo(Node) == .@"struct");
15:     assert(field_back_enum != field_next_enum);
16: 
17:     const field_back = @tagName(field_back_enum);
18:     const field_next = @tagName(field_next_enum);
19:     assert(@FieldType(Node, field_back) == ?*Node);
20:     assert(@FieldType(Node, field_next) == ?*Node);
21: 
22:     return struct {
23:         const DoublyLinkedList = @This();
24: 
25:         tail: ?*Node = null,
26:         count: u32 = 0,
27: 
28:         pub fn verify(list: *const DoublyLinkedList) void {
29:             assert((list.count == 0) == (list.tail == null));
30: 
31:             var count: u32 = 0;
32:             var iterator = list.tail;
33: 
34:             if (iterator) |node| {
35:                 assert(@field(node, field_next) == null);
36:             }
37: 
38:             while (iterator) |node| {
39:                 const back = @field(node, field_back);
40:                 if (back) |back_node| {
41:                     assert(back_node != node); // There are no cycles.
42:                     assert(@field(back_node, field_next) == node);
43:                 }
44:                 count += 1;
45:                 iterator = back;
46:             }
47:             assert(count == list.count);
48:         }
49: 
50:         fn contains(list: *const DoublyLinkedList, target: *const Node) bool {
51:             var count: u32 = 0;
52: 
53:             var iterator = list.tail;
54:             while (iterator) |node| {
55:                 if (node == target) return true;
56:                 iterator = @field(node, field_back);
57:                 count += 1;
58:             }
59: 
60:             assert(count == list.count);
61:             return false;
62:         }
63: 
64:         pub fn empty(list: *const DoublyLinkedList) bool {
65:             assert((list.count == 0) == (list.tail == null));
66:             return list.count == 0;
67:         }
68: 
69:         pub fn push(list: *DoublyLinkedList, node: *Node) void {
70:             if (constants.verify) assert(!list.contains(node));
71:             if (constants.verify) list.verify();
72:             assert(@field(node, field_back) == null);
73:             assert(@field(node, field_next) == null);
74: 
75:             if (list.tail) |tail| {
76:                 assert(list.count > 0);
77:                 assert(@field(tail, field_next) == null);
78: 
79:                 @field(node, field_back) = tail;
80:                 @field(tail, field_next) = node;
81:             } else {
82:                 assert(list.count == 0);
83:             }
84: 
85:             list.tail = node;
86:             list.count += 1;
87:         }
88: 
89:         pub fn pop(list: *DoublyLinkedList) ?*Node {
90:             if (constants.verify) list.verify();
91: 
92:             if (list.tail) |tail_old| {
93:                 assert(list.count > 0);
94:                 assert(@field(tail_old, field_next) == null);
95: 
96:                 list.tail = @field(tail_old, field_back);
97:                 list.count -= 1;
98: 
99:                 if (list.tail) |tail_new| {
100:                     assert(@field(tail_new, field_next) == tail_old);
101:                     @field(tail_new, field_next) = null;
102:                 }
103: 
104:                 @field(tail_old, field_back) = null;
105:                 return tail_old;
106:             } else {
107:                 assert(list.count == 0);
108:                 return null;
109:             }
110:         }
111: 
112:         pub fn remove(list: *DoublyLinkedList, node: *Node) void {
113:             if (constants.verify) assert(list.contains(node));
114:             if (constants.verify) list.verify();
115:             assert(list.count > 0);
116:             assert(list.tail != null);
117: 
118:             const tail = list.tail.?;
119: 
120:             if (node == tail) {
121:                 // Pop the last element of the list.
122:                 assert(@field(node, field_next) == null);
123:                 list.tail = @field(node, field_back);
124:             }
125:             if (@field(node, field_back)) |node_back| {
126:                 assert(@field(node_back, field_next).? == node);
127:                 @field(node_back, field_next) = @field(node, field_next);
128:             }
129:             if (@field(node, field_next)) |node_next| {
130:                 assert(@field(node_next, field_back).? == node);
131:                 @field(node_next, field_back) = @field(node, field_back);
132:             }
133:             @field(node, field_back) = null;
134:             @field(node, field_next) = null;
135:             list.count -= 1;
136: 
137:             if (constants.verify) list.verify();
138:             assert((list.count == 0) == (list.tail == null));
139:         }
140:     };
141: }
