161: test "DoublyLinkedList fuzz" {
162:     // Ensure that The DoublyLinkedList's extra-verification is enabled.
163:     comptime assert(constants.verify);
164: 
165:     const allocator = std.testing.allocator;
166: 
167:     var prng = stdx.PRNG.from_seed_testing();
168: 
169:     const Node = struct { id: u32, back: ?*@This() = null, next: ?*@This() = null };
170:     const List = DoublyLinkedListType(Node, .back, .next);
171: 
172:     const nodes_count = 1024;
173:     const events_max = 1 << 15;
174: 
175:     const Event = enum { push, pop, remove };
176:     const event_weights: stdx.PRNG.EnumWeightsType(Event) = .{ .push = 10, .pop = 1, .remove = 8 };
177: 
178:     const nodes = try allocator.alloc(Node, nodes_count);
179:     defer allocator.free(nodes);
180: 
181:     for (nodes, 0..) |*node, i| node.* = .{ .id = @intCast(i) };
182: 
183:     var nodes_free = try std.DynamicBitSetUnmanaged.initFull(allocator, nodes_count);
184:     defer nodes_free.deinit(allocator);
185: 
186:     var list = List{};
187:     var list_model = stdx.BoundedArrayType(u32, nodes_count){};
188: 
189:     for (0..events_max) |_| {
190:         assert(list_model.count() <= nodes_count);
191:         assert(list_model.count() == list.count);
192:         assert(list_model.empty() == list.empty());
193: 
194:         const event = prng.enum_weighted(Event, event_weights);
195:         switch (event) {
196:             .push => {
197:                 const node_free = nodes_free.findFirstSet() orelse continue;
198:                 const node = &nodes[node_free];
199: 
200:                 list.push(node);
201:                 list_model.push(node.id);
202:                 nodes_free.unset(node.id);
203:             },
204:             .pop => {
205:                 if (list.pop()) |node| {
206:                     assert(node.back == null);
207:                     assert(node.next == null);
208: 
209:                     const node_id = list_model.pop().?;
210:                     assert(node_id == node.id);
211:                     assert(nodes_free.count() < nodes_count);
212:                     assert(!nodes_free.isSet(node_id));
213: 
214:                     nodes_free.set(node_id);
215:                 } else {
216:                     assert(nodes_free.count() == nodes_count);
217:                     assert(list_model.empty());
218:                 }
219:             },
220:             .remove => {
221:                 if (list_model.count() == 0) continue;
222: 
223:                 const list_index = prng.index(list_model.slice());
224:                 const node_id = list_model.get(list_index);
225:                 assert(node_id == list_model.ordered_remove(list_index));
226:                 assert(!nodes_free.isSet(node_id));
227: 
228:                 list.remove(&nodes[node_id]);
229:                 assert(nodes[node_id].back == null);
230:                 assert(nodes[node_id].next == null);
231: 
232:                 nodes_free.set(node_id);
233:             },
234:         }
235:     }
236: }
