6: const QueueLink = extern struct {
7:     next: ?*QueueLink = null,
8: };
9: 
10: /// An intrusive first in/first out linked list.
11: /// The element type T must have a field called "link" of type QueueType(T).Link.
12: pub fn QueueType(comptime T: type) type {
13:     return struct {
14:         any: QueueAny,
15: 
16:         pub const Link = QueueLink;
17:         const Queue = @This();
18: 
19:         pub inline fn init(options: struct {
20:             name: ?[]const u8,
21:             verify_push: bool = true,
22:         }) Queue {
23:             return .{ .any = .{
24:                 .name = options.name,
25:                 .verify_push = options.verify_push,
26:             } };
27:         }
28: 
29:         pub inline fn push(self: *Queue, link: *T) void {
30:             self.any.push(&link.link);
31:         }
32: 
33:         pub inline fn pop(self: *Queue) ?*T {
34:             const link = self.any.pop() orelse return null;
35:             return @alignCast(@fieldParentPtr("link", link));
36:         }
37: 
38:         pub inline fn peek_last(self: *const Queue) ?*T {
39:             const link = self.any.peek_last() orelse return null;
40:             return @alignCast(@fieldParentPtr("link", link));
41:         }
42: 
43:         pub inline fn peek(self: *const Queue) ?*T {
44:             const link = self.any.peek() orelse return null;
45:             return @alignCast(@fieldParentPtr("link", link));
46:         }
47: 
48:         pub fn count(self: *const Queue) u64 {
49:             return self.any.count;
50:         }
51: 
52:         pub inline fn empty(self: *const Queue) bool {
53:             return self.any.empty();
54:         }
55: 
56:         /// Returns whether the linked list contains the given *exact element* (pointer comparison).
57:         pub inline fn contains(self: *const Queue, elem_needle: *const T) bool {
58:             return self.any.contains(&elem_needle.link);
59:         }
60: 
61:         /// Remove an element from the Queue. Asserts that the element is
62:         /// in the Queue. This operation is O(N), if this is done often you
63:         /// probably want a different data structure.
64:         pub inline fn remove(self: *Queue, to_remove: *T) void {
65:             self.any.remove(&to_remove.link);
66:         }
67: 
68:         pub inline fn reset(self: *Queue) void {
69:             self.any.reset();
70:         }
71: 
72:         pub inline fn iterate(self: *const Queue) Iterator {
73:             return .{ .any = self.any.iterate() };
74:         }
75: 
76:         pub const Iterator = struct {
77:             any: QueueAny.Iterator,
78: 
79:             pub inline fn next(iterator: *@This()) ?*T {
80:                 const link = iterator.any.next() orelse return null;
81:                 return @alignCast(@fieldParentPtr("link", link));
82:             }
83:         };
84:     };
85: }
86: 
87: // Non-generic implementation for smaller binary and faster compile times.
88: const QueueAny = struct {
89:     in: ?*QueueLink = null,
90:     out: ?*QueueLink = null,
91:     count: u64 = 0,
92: 
93:     // This should only be null if you're sure we'll never want to monitor `count`.
94:     name: ?[]const u8,
95: 
96:     // If the number of elements is large, the constants.verify check in push() can be too
97:     // expensive. Allow the user to gate it. Could also be a comptime param?
98:     verify_push: bool = true,
99: 
100:     pub fn push(self: *QueueAny, link: *QueueLink) void {
101:         if (constants.verify and self.verify_push) assert(!self.contains(link));
102: 
103:         assert(link.next == null);
104:         if (self.in) |in| {
105:             in.next = link;
106:             self.in = link;
107:         } else {
108:             assert(self.out == null);
109:             self.in = link;
110:             self.out = link;
111:         }
112:         self.count += 1;
113:     }
114: 
115:     pub fn pop(self: *QueueAny) ?*QueueLink {
116:         const result = self.out orelse return null;
117:         self.out = result.next;
118:         result.next = null;
119:         if (self.in == result) self.in = null;
120:         self.count -= 1;
121:         return result;
122:     }
123: 
124:     pub fn peek_last(self: *const QueueAny) ?*QueueLink {
125:         return self.in;
126:     }
127: 
128:     pub fn peek(self: *const QueueAny) ?*QueueLink {
129:         return self.out;
130:     }
131: 
132:     pub fn empty(self: *const QueueAny) bool {
133:         return self.peek() == null;
134:     }
135: 
136:     pub fn contains(self: *const QueueAny, needle: *const QueueLink) bool {
137:         var iterator = self.peek();
138:         while (iterator) |link| : (iterator = link.next) {
139:             if (link == needle) return true;
140:         }
141:         return false;
142:     }
143: 
144:     pub fn remove(self: *QueueAny, to_remove: *QueueLink) void {
145:         if (to_remove == self.out) {
146:             _ = self.pop();
147:             return;
148:         }
149:         var it = self.out;
150:         while (it) |link| : (it = link.next) {
151:             if (to_remove == link.next) {
152:                 if (to_remove == self.in) self.in = link;
153:                 link.next = to_remove.next;
154:                 to_remove.next = null;
155:                 self.count -= 1;
156:                 break;
157:             }
158:         } else unreachable;
159:     }
160: 
161:     pub fn reset(self: *QueueAny) void {
162:         self.* = .{
163:             .name = self.name,
164:             .verify_push = self.verify_push,
165:         };
166:     }
167: 
168:     pub fn iterate(self: *const QueueAny) Iterator {
169:         return .{
170:             .head = self.out,
171:         };
172:     }
173: 
174:     const Iterator = struct {
175:         head: ?*QueueLink,
176: 
177:         fn next(iterator: *Iterator) ?*QueueLink {
178:             const head = iterator.head orelse return null;
179:             iterator.head = head.next;
180:             return head;
181:         }
182:     };
183: };
