257: test "Queue: fuzz" {
258:     const stdx = @import("stdx");
259:     const fuzz = @import("./testing/fuzz.zig");
260: 
261:     const Item = struct {
262:         value: u64,
263:         link: QueueType(@This()).Link,
264:     };
265:     const Queue = QueueType(Item);
266:     const Model = stdx.RingBufferType(u64, .slice);
267: 
268:     const gpa = std.testing.allocator;
269:     var prng = stdx.PRNG.from_seed_testing();
270: 
271:     for (0..100) |_| {
272:         const N = 1000;
273: 
274:         var queue = Queue.init(.{
275:             .name = "fuzz",
276:         });
277:         var model = try Model.init(gpa, N);
278:         defer model.deinit(gpa);
279: 
280:         // Implement "remove" by copy.
281:         var model_scratch = try Model.init(gpa, N);
282:         defer model_scratch.deinit(gpa);
283: 
284:         var items = try gpa.alloc(Item, N);
285:         defer gpa.free(items);
286: 
287:         for (items, 0..) |*item, value| {
288:             item.* = .{ .value = value, .link = .{} };
289:         }
290: 
291:         var free: std.ArrayListUnmanaged(usize) = .{};
292:         defer free.deinit(gpa);
293: 
294:         try free.ensureTotalCapacity(gpa, N);
295:         for (items, 0..) |_, index| {
296:             free.appendAssumeCapacity(index);
297:         }
298: 
299:         const Declarations = fuzz.DeclEnumExcludingType(
300:             Queue,
301:             &.{ .Link, .Iterator, .init, .count, .empty },
302:         );
303:         const weights = fuzz.random_enum_weights(&prng, Declarations);
304: 
305:         for (0..N) |_| {
306:             switch (prng.enum_weighted(Declarations, weights)) {
307:                 .push => {
308:                     if (free.items.len > 0) {
309:                         const index = free.swapRemove(prng.index(free.items));
310:                         model.push_assume_capacity(items[index].value);
311:                         queue.push(&items[index]);
312:                     }
313:                 },
314:                 .pop => {
315:                     if (model.empty()) {
316:                         assert(queue.pop() == null);
317:                     } else {
318:                         const item = queue.pop().?;
319:                         assert(item.value == model.pop().?);
320: 
321:                         const index = @divExact(
322:                             (@intFromPtr(item) - @intFromPtr(items.ptr)),
323:                             @sizeOf(Item),
324:                         );
325:                         free.appendAssumeCapacity(index);
326:                     }
327:                 },
328:                 .peek => {
329:                     if (model.head()) |head| {
330:                         assert(queue.peek().?.value == head);
331:                     } else {
332:                         assert(queue.peek() == null);
333:                     }
334:                 },
335:                 .peek_last => {
336:                     if (model.tail()) |tail| {
337:                         assert(queue.peek_last().?.value == tail);
338:                     } else {
339:                         assert(queue.peek_last() == null);
340:                     }
341:                 },
342:                 .contains => {
343:                     const item = &items[prng.index(items)];
344: 
345:                     const model_contains = model_contains: {
346:                         var it = model.iterator();
347:                         while (it.next()) |v| {
348:                             if (v == item.value) {
349:                                 break :model_contains true;
350:                             }
351:                         }
352:                         break :model_contains false;
353:                     };
354:                     assert(model_contains == queue.contains(item));
355:                 },
356:                 .remove => {
357:                     const item = &items[prng.index(items)];
358:                     if (queue.contains(item)) {
359:                         queue.remove(item);
360: 
361:                         assert(model_scratch.empty());
362:                         while (model.pop()) |value| {
363:                             if (value != item.value) {
364:                                 model_scratch.push_assume_capacity(value);
365:                             }
366:                         }
367:                         std.mem.swap(Model, &model, &model_scratch);
368:                     }
369:                 },
370:                 .reset => {
371:                     model.clear();
372:                     queue.reset();
373:                 },
374:                 .iterate => {
375:                     var queue_iterator = queue.iterate();
376:                     var model_iterator = model.iterator();
377: 
378:                     while (queue_iterator.next()) |queue_item| {
379:                         const model_item = model_iterator.next().?;
380:                         assert(queue_item.value == model_item);
381:                     }
382:                     assert(model_iterator.next() == null);
383:                     assert(queue_iterator.next() == null);
384:                 },
385:             }
386:             assert(queue.count() == model.count);
387:             assert(queue.empty() == model.empty());
388:         }
389:     }
390: }
