11: /// An intrusive last in/first out linked list (LIFO).
12: /// The element type T must have a field called "next" of type StackType(T).Link.
13: pub fn StackType(comptime T: type) type {
14:     return struct {
15:         any: StackAny,
16: 
17:         pub const Link = StackLink;
18:         const Stack = @This();
19: 
20:         pub inline fn init(options: struct {
21:             capacity: u32,
22:             verify_push: bool,
23:         }) Stack {
24:             return .{ .any = .{
25:                 .capacity = options.capacity,
26:                 .verify_push = options.verify_push,
27:             } };
28:         }
29: 
30:         pub inline fn count(self: *Stack) u32 {
31:             return self.any.count;
32:         }
33: 
34:         pub inline fn capacity(self: *Stack) u32 {
35:             return self.any.capacity;
36:         }
37: 
38:         /// Pushes a new node to the first position of the Stack.
39:         pub inline fn push(self: *Stack, node: *T) void {
40:             self.any.push(&node.link);
41:         }
42: 
43:         /// Returns the first element of the Stack list, and removes it.
44:         pub inline fn pop(self: *Stack) ?*T {
45:             const link = self.any.pop() orelse return null;
46:             return @fieldParentPtr("link", link);
47:         }
48: 
49:         /// Returns the first element of the Stack list, but does not remove it.
50:         pub inline fn peek(self: *const Stack) ?*T {
51:             const link = self.any.peek() orelse return null;
52:             return @fieldParentPtr("link", link);
53:         }
54: 
55:         /// Checks if the Stack is empty.
56:         pub inline fn empty(self: *const Stack) bool {
57:             return self.any.empty();
58:         }
59: 
60:         /// Returns whether the linked list contains the given *exact element* (pointer comparison).
61:         inline fn contains(self: *const Stack, needle: *const T) bool {
62:             return self.any.contains(&needle.link);
63:         }
64:     };
65: }
66: 
67: // Non-generic implementation for smaller binary and faster compile times.
68: const StackAny = struct {
69:     head: ?*StackLink = null,
70: 
71:     count: u32 = 0,
72:     capacity: u32,
73: 
74:     // If the number of elements is large, the constants.verify check in push() can be too
75:     // expensive. Allow the user to gate it.
76:     verify_push: bool,
77: 
78:     fn push(self: *StackAny, link: *StackLink) void {
79:         if (constants.verify and self.verify_push) assert(!self.contains(link));
80: 
81:         assert((self.count == 0) == (self.head == null));
82:         assert(link.next == null);
83:         assert(self.count < self.capacity);
84: 
85:         // Insert the new element at the head.
86:         link.next = self.head;
87:         self.head = link;
88:         self.count += 1;
89:     }
90: 
91:     fn pop(self: *StackAny) ?*StackLink {
92:         assert((self.count == 0) == (self.head == null));
93: 
94:         const link = self.head orelse return null;
95:         self.head = link.next;
96:         link.next = null;
97:         self.count -= 1;
98:         return link;
99:     }
100: 
101:     fn peek(self: *const StackAny) ?*StackLink {
102:         return self.head;
103:     }
104: 
105:     fn empty(self: *const StackAny) bool {
106:         assert((self.count == 0) == (self.head == null));
107:         return self.head == null;
108:     }
109: 
110:     fn contains(self: *const StackAny, needle: *const StackLink) bool {
111:         assert(self.count <= self.capacity);
112:         var next = self.head;
113:         for (0..self.count + 1) |_| {
114:             const link = next orelse return false;
115:             if (link == needle) return true;
116:             next = link.next;
117:         } else unreachable;
118:     }
119: };
