121: test "Stack: fuzz" {
122:     // Fuzzy test to compare behavior of Stack against std.ArrayList (reference model).
123:     comptime assert(constants.verify);
124: 
125:     const allocator = std.testing.allocator;
126: 
127:     var prng = stdx.PRNG.from_seed_testing();
128: 
129:     const Item = struct {
130:         id: u32,
131:         link: StackType(@This()).Link,
132:     };
133:     const Stack = StackType(Item);
134: 
135:     const item_count_max = 1024;
136:     const events_max = 1 << 10;
137: 
138:     const Event = enum { push, pop };
139:     const event_weights = stdx.PRNG.EnumWeightsType(Event){
140:         .push = 2,
141:         .pop = 1,
142:     };
143: 
144:     // Allocate a pool of nodes.
145:     var items = try allocator.alloc(Item, item_count_max);
146:     defer allocator.free(items);
147: 
148:     for (items, 0..) |*item, i| {
149:         item.* = Item{ .id = @intCast(i), .link = .{} };
150:     }
151: 
152:     // A bit set that tracks which nodes are available.
153:     var items_free = try std.DynamicBitSetUnmanaged.initFull(allocator, item_count_max);
154:     defer items_free.deinit(allocator);
155: 
156:     var stack = Stack.init(.{
157:         .capacity = item_count_max,
158:         .verify_push = true,
159:     });
160: 
161:     // Reference model: a dynamic array of node IDs in Stack order (last is the top).
162:     var model = try std.ArrayList(u32).initCapacity(allocator, item_count_max);
163:     defer model.deinit();
164: 
165:     // Run a sequence of randomized events.
166:     for (0..events_max) |_| {
167:         assert(model.items.len <= item_count_max);
168:         assert(model.items.len == stack.count());
169:         assert(model.items.len == 0 or !stack.empty());
170: 
171:         const event = prng.enum_weighted(Event, event_weights);
172:         switch (event) {
173:             .push => {
174:                 // Only push if a free node is available.
175:                 const free_index = items_free.findFirstSet() orelse continue;
176:                 const item = &items[free_index];
177:                 stack.push(item);
178:                 try model.append(item.id);
179:                 items_free.unset(item.id);
180:             },
181:             .pop => {
182:                 if (stack.pop()) |item| {
183:                     // The reference model should have the same node at the top.
184:                     const id = item.id;
185:                     const expected = model.pop();
186:                     assert(id == expected);
187:                     items_free.set(id);
188:                 } else {
189:                     assert(model.items.len == 0);
190:                     assert(stack.empty());
191:                     assert(stack.count() == 0);
192:                     assert(stack.peek() == null);
193:                 }
194:             },
195:         }
196:         // Verify that peek() returns the same as the last element in our model.
197:         if (model.items.len > 0) {
198:             const top = stack.peek() orelse unreachable;
199:             const top_ref = model.pop().?;
200:             assert(top.id == top_ref);
201:             try model.append(top_ref);
202:         } else {
203:             assert(stack.empty());
204:             assert(stack.count() == 0);
205:             assert(stack.peek() == null);
206:         }
207:     }
208: 
209:     // Finally, empty the Stack and ensure our reference model agrees.
210:     while (stack.pop()) |item| {
211:         const id = item.id;
212:         const expected = model.pop();
213:         assert(id == expected);
214:         items_free.set(id);
215:     }
216:     assert(model.items.len == 0);
217:     assert(stack.empty());
218:     assert(stack.count() == 0);
219:     assert(stack.peek() == null);
220: }
