222: test "Stack: push/pop/peek/empty" {
223:     const testing = @import("std").testing;
224:     const Item = struct { link: StackLink = .{} };
225: 
226:     var one: Item = .{};
227:     var two: Item = .{};
228:     var three: Item = .{};
229: 
230:     var stack: StackType(Item) = StackType(Item).init(.{
231:         .capacity = 3,
232:         .verify_push = true,
233:     });
234: 
235:     try testing.expect(stack.empty());
236: 
237:     // Push one element and verify
238:     stack.push(&one);
239:     try testing.expect(!stack.empty());
240:     try testing.expectEqual(@as(?*Item, &one), stack.peek());
241:     try testing.expect(stack.contains(&one));
242:     try testing.expect(!stack.contains(&two));
243:     try testing.expect(!stack.contains(&three));
244: 
245:     // Push two more elements
246:     stack.push(&two);
247:     stack.push(&three);
248:     try testing.expect(!stack.empty());
249:     try testing.expectEqual(@as(?*Item, &three), stack.peek());
250:     try testing.expect(stack.contains(&one));
251:     try testing.expect(stack.contains(&two));
252:     try testing.expect(stack.contains(&three));
253: 
254:     // Pop elements and check Stack order
255:     try testing.expectEqual(@as(?*Item, &three), stack.pop());
256:     try testing.expectEqual(@as(?*Item, &two), stack.pop());
257:     try testing.expectEqual(@as(?*Item, &one), stack.pop());
258:     try testing.expect(stack.empty());
259:     try testing.expectEqual(@as(?*Item, null), stack.pop());
