1: const std = @import("std");
2: const stdx = @import("stdx");
3: const assert = std.debug.assert;
4: const maybe = stdx.maybe;
5: const Elem = std.meta.Elem;
6: 
7: const binary_search = @import("lsm/binary_search.zig");
8: 
9: /// LSM Tree is a sorted array with a monocle and a top hat.
10: ///
11: /// We want to iterate it in both directions:
12: /// - For CDC, you want to learn about all new objects with timestamp>threshold.
13: /// - For paginated timelines, you want to learn about past objects with timestamp<threshold.
14: ///
15: /// Sadly, this can't be implemented via just a single branch near the end of the system, we need to
16: /// change a whole bunch of `<` to `>` throughout the stack.
17: ///
18: /// Direction encapsulate the logic of "if ascending use < if descending use >". The mnemonic is
19: /// that usual comparison is horizontal along a number line, but Direction-aware is vertical.
20: ///
21: /// In other words, `key_min` and `key_max` track natural ordering, while `key_lower` and
22: /// `key_upper` are direction-aware.
23: pub const Direction = enum(u1) {
24:     ascending = 0,
25:     descending = 1,
26: 
27:     pub fn reverse(d: Direction) Direction {
28:         return switch (d) {
29:             .ascending => .descending,
30:             .descending => .ascending,
31:         };
32:     }
33: 
34:     pub inline fn cmp(
35:         d: Direction,
36:         a: anytype,
37:         comptime op: enum { @"<", @"<=" },
38:         b: @TypeOf(a),
39:     ) bool {
40:         return switch (op) {
41:             .@"<" => switch (d) {
42:                 .ascending => a < b,
43:                 .descending => a > b,
44:             },
45:             .@"<=" => switch (d) {
46:                 .ascending => a <= b,
47:                 .descending => a >= b,
48:             },
49:         };
50:     }
51: 
52:     pub inline fn lower(d: Direction, a: anytype, b: @TypeOf(a)) @TypeOf(a) {
53:         return if (d.cmp(a, .@"<", b)) a else b;
54:     }
55: 
56:     pub inline fn upper(d: Direction, a: anytype, b: @TypeOf(a)) @TypeOf(a) {
57:         return if (d.cmp(a, .@"<", b)) b else a;
58:     }
59: 
60:     pub inline fn slice_peek(d: Direction, slice: anytype) *const Elem(@TypeOf(slice)) {
61:         assert(slice.len > 0);
62:         return switch (d) {
63:             .ascending => &slice[0],
64:             .descending => &slice[slice.len - 1],
65:         };
66:     }
67: 
68:     pub inline fn slice_pop(
69:         d: Direction,
70:         slice: anytype,
71:     ) struct { Elem(@TypeOf(slice)), @TypeOf(slice) } {
72:         assert(slice.len > 0);
73:         return switch (d) {
74:             .ascending => .{ slice[0], slice[1..] },
75:             .descending => .{ slice[slice.len - 1], slice[0 .. slice.len - 1] },
76:         };
77:     }
78: 
79:     pub inline fn slice_lower_bound(
80:         direction: Direction,
81:         comptime Key: type,
82:         comptime Value: type,
83:         comptime key_from_value: fn (*const Value) callconv(.@"inline") Key,
84:         slice: []const Value,
85:         key: Key,
86:     ) []const Value {
87:         maybe(slice.len == 0);
88:         switch (direction) {
89:             .ascending => {
90:                 const start = binary_search.binary_search_values_upsert_index(
91:                     Key,
92:                     Value,
93:                     key_from_value,
94:                     slice,
95:                     key,
96:                     .{ .mode = .lower_bound },
97:                 );
98: 
99:                 return if (start == slice.len) &.{} else slice[start..];
100:             },
101:             .descending => {
102:                 const end = end: {
103:                     const index = binary_search.binary_search_values_upsert_index(
104:                         Key,
105:                         Value,
106:                         key_from_value,
107:                         slice,
108:                         key,
109:                         .{ .mode = .upper_bound },
110:                     );
111:                     break :end index + @intFromBool(
112:                         index < slice.len and key_from_value(&slice[index]) <= key,
113:                     );
114:                 };
115: 
116:                 return if (end == 0) &.{} else slice[0..end];
117:             },
118:         }
119:     }
120: };
