1: const std = @import("std");
2: const assert = std.debug.assert;
3: const math = std.math;
4: 
5: const stdx = @import("stdx");
6: 
7: const constants = @import("../constants.zig");
8: 
9: pub const Config = struct {
10:     mode: enum { lower_bound, upper_bound } = .lower_bound,
11:     prefetch: bool = true,
12: };
13: 
14: // TODO The Zig self hosted compiler will implement inlining itself before passing the IR to llvm,
15: // which should eliminate the current poor codegen of key_from_value.
16: 
17: /// Returns either the index of the value equal to `key`,
18: /// or if there is no such value then the index where `key` would be inserted.
19: ///
20: /// In other words, return `i` such that both:
21: /// * key <= key_from_value(values[i]) or i == values.len
22: /// * key_value_from(values[i-1]) <= key or i == 0
23: ///
24: /// If `values` contains duplicated matches, then returns
25: /// the first index when `Config.mode == .lower_bound`,
26: /// or the last index when `Config.mode == .upper_bound`.
27: /// This invariant can be expressed as:
28: /// * key_value_from(values[i-1]) < key or i == 0 when Config.mode == .lower_bound.
29: /// * key < key_value_from(values[i+1]) or i == values.len when Config.mode == .upper_bound.
30: ///
31: /// Expects `values` to be sorted by key.
32: /// Doesn't perform the extra key comparison to determine if the match is exact.
33: pub fn binary_search_values_upsert_index(
34:     comptime Key: type,
35:     comptime Value: type,
36:     comptime key_from_value: fn (*const Value) callconv(.@"inline") Key,
37:     values: []const Value,
38:     key: Key,
39:     comptime config: Config,
40: ) u32 {
41:     if (values.len == 0) return 0;
42: 
43:     var offset: usize = 0;
44:     var length: usize = values.len;
45:     while (length > 1) {
46:         if (constants.verify) {
47:             assert(offset == 0 or switch (comptime config.mode) {
48:                 .lower_bound => key_from_value(&values[offset - 1]) < key,
49:                 .upper_bound => key_from_value(&values[offset - 1]) <= key,
50:             });
51: 
52:             assert(offset + length == values.len or switch (comptime config.mode) {
53:                 .lower_bound => key <= key_from_value(&values[offset + length]),
54:                 .upper_bound => key < key_from_value(&values[offset + length]),
55:             });
56:         }
57: 
58:         const half = length / 2;
59:         if (config.prefetch) {
60:             // Prefetching:
61:             // ARRAY LAYOUTS FOR COMPARISON-BASED SEARCHING, page 18.
62:             // https://arxiv.org/abs/1509.05053.
63:             //
64:             // Prefetching the two possible positions we'd need for the next iteration:
65:             //
66:             // [....................mid....................]
67:             //           ^                       ^
68:             //       one quarter          three quarters.
69: 
70:             // We need to use pointer arithmetic and disable runtime safety to avoid bounds checks,
71:             // otherwise prefetching would harm the performance instead of improving it.
72:             // Since these pointers are never dereferenced, it's safe to dismiss this extra cost
73:             // here.
74:             @setRuntimeSafety(constants.verify);
75:             const one_quarter = values.ptr + offset + half / 2;
76:             const three_quarters = one_quarter + half;
77: 
78:             // @sizeOf(Value) can be greater than a single cache line.
79:             // In that case, we need to prefetch multiple cache lines for a single value:
80:             comptime stdx.maybe(@sizeOf(Value) > constants.cache_line_size);
81:             const CacheLineBytes = [*]const [constants.cache_line_size]u8;
82:             const cache_lines_per_value = comptime stdx.div_ceil(
83:                 @sizeOf(Value),
84:                 constants.cache_line_size,
85:             );
86:             inline for (0..cache_lines_per_value) |i| {
87:                 // Locality = 0 means no temporal locality. That is, the data can be immediately
88:                 // dropped from the cache after it is accessed.
89:                 const options: std.builtin.PrefetchOptions = .{
90:                     .rw = .read,
91:                     .locality = 0,
92:                     .cache = .data,
93:                 };
94: 
95:                 @prefetch(@as(CacheLineBytes, @ptrCast(@alignCast(one_quarter))) + i, options);
96:                 @prefetch(@as(CacheLineBytes, @ptrCast(@alignCast(three_quarters))) + i, options);
97:             }
98:         }
99: 
100:         const mid = offset + half;
101: 
102:         // For exact matches, takes the first half if `mode == .lower_bound`,
103:         // or the second half if `mode == .upper_bound`.
104:         const take_upper_half: bool = (switch (comptime config.mode) {
105:             .lower_bound => key_from_value(&values[mid]) < key,
106:             .upper_bound => key_from_value(&values[mid]) <= key,
107:         });
108: 
109:         if (take_upper_half) {
110:             @branchHint(.unpredictable);
111:             offset = mid;
112:         }
113: 
114:         length -= half;
115:     }
116: 
117:     if (constants.verify) {
118:         assert(length == 1);
119: 
120:         assert(offset == 0 or switch (comptime config.mode) {
121:             .lower_bound => key_from_value(&values[offset - 1]) < key,
122:             .upper_bound => key_from_value(&values[offset - 1]) <= key,
123:         });
124: 
125:         assert(offset + length == values.len or switch (comptime config.mode) {
126:             .lower_bound => key <= key_from_value(&values[offset + length]),
127:             .upper_bound => key < key_from_value(&values[offset + length]),
128:         });
129:     }
130: 
131:     offset += @intFromBool(key_from_value(&values[offset]) < key);
132: 
133:     if (constants.verify) {
134:         assert(offset == 0 or switch (config.mode) {
135:             .lower_bound => key_from_value(&values[offset - 1]) < key,
136:             .upper_bound => key_from_value(&values[offset - 1]) <= key,
137:         });
138:         assert(offset >= values.len - 1 or switch (config.mode) {
139:             .lower_bound => key <= key_from_value(&values[offset + 1]),
140:             .upper_bound => key < key_from_value(&values[offset + 1]),
141:         });
142:         assert(offset == values.len or
143:             key <= key_from_value(&values[offset]));
144:     }
145: 
146:     return @intCast(offset);
147: }
148: 
149: pub inline fn binary_search_keys_upsert_index(
150:     comptime Key: type,
151:     keys: []const Key,
152:     key: Key,
153:     comptime config: Config,
154: ) u32 {
155:     return binary_search_values_upsert_index(
156:         Key,
157:         Key,
158:         struct {
159:             inline fn key_from_key(k: *const Key) Key {
160:                 return k.*;
161:             }
162:         }.key_from_key,
163:         keys,
164:         key,
165:         config,
166:     );
167: }
