169: const BinarySearchResult = struct {
170:     index: u32,
171:     exact: bool,
172: };
173: 
174: pub inline fn binary_search_values(
175:     comptime Key: type,
176:     comptime Value: type,
177:     comptime key_from_value: fn (*const Value) callconv(.@"inline") Key,
178:     values: []const Value,
179:     key: Key,
180:     comptime config: Config,
181: ) ?*const Value {
182:     const index = binary_search_values_upsert_index(
183:         Key,
184:         Value,
185:         key_from_value,
186:         values,
187:         key,
188:         config,
189:     );
190:     const exact = index < values.len and key_from_value(&values[index]) == key;
191: 
192:     if (exact) {
193:         const value = &values[index];
194:         assert(key == key_from_value(value));
195:         return value;
196:     } else {
197:         // TODO: Figure out how to fuzz this without causing asymptotic
198:         //       slowdown in all fuzzers
199:         return null;
200:     }
201: }
