203: pub inline fn binary_search_keys(
204:     comptime Key: type,
205:     keys: []const Key,
206:     key: Key,
207:     comptime config: Config,
208: ) BinarySearchResult {
209:     const index = binary_search_keys_upsert_index(Key, keys, key, config);
210:     return .{
211:         .index = index,
212:         .exact = index < keys.len and keys[index] == key,
213:     };
