216: pub const BinarySearchRangeUpsertIndexes = struct {
217:     start: u32,
218:     end: u32,
219: };
220: 
221: /// Same semantics of `binary_search_values_upsert_indexes`:
222: /// Returns either the indexes of the values equal to `key_min` and `key_max`,
223: /// or the indexes where they would be inserted.
224: ///
225: /// Expects `values` to be sorted by key.
226: /// If `values` contains duplicated matches, then returns
227: /// the first index for `key_min` and the last index for `key_max`.
228: ///
229: /// Doesn't perform the extra key comparison to determine if the match is exact.
230: pub inline fn binary_search_values_range_upsert_indexes(
231:     comptime Key: type,
232:     comptime Value: type,
233:     comptime key_from_value: fn (*const Value) callconv(.@"inline") Key,
234:     values: []const Value,
235:     key_min: Key,
236:     key_max: Key,
237: ) BinarySearchRangeUpsertIndexes {
238:     assert(key_min <= key_max);
239: 
240:     const start = binary_search_values_upsert_index(
241:         Key,
242:         Value,
243:         key_from_value,
244:         values,
245:         key_min,
246:         .{ .mode = .lower_bound },
247:     );
248: 
249:     if (start == values.len) return .{
250:         .start = start,
251:         .end = start,
252:     };
253: 
254:     const end = binary_search_values_upsert_index(
255:         Key,
256:         Value,
257:         key_from_value,
258:         values[start..],
259:         key_max,
260:         .{ .mode = .upper_bound },
261:     );
262: 
263:     return .{
264:         .start = start,
265:         .end = start + end,
266:     };
267: }
