269: pub inline fn binary_search_keys_range_upsert_indexes(
270:     comptime Key: type,
271:     keys: []const Key,
272:     key_min: Key,
273:     key_max: Key,
274: ) BinarySearchRangeUpsertIndexes {
275:     return binary_search_values_range_upsert_indexes(
276:         Key,
277:         Key,
278:         struct {
279:             inline fn key_from_key(k: *const Key) Key {
280:                 return k.*;
281:             }
282:         }.key_from_key,
283:         keys,
284:         key_min,
285:         key_max,
286:     );
287: }
288: 
289: pub const BinarySearchRange = struct {
290:     start: u32,
291:     count: u32,
292: };
293: 
294: /// Returns the index of the first value greater than or equal to `key_min` and
295: /// the count of elements until the last value less than or equal to `key_max`.
296: ///
297: /// Expects `values` to be sorted by key.
298: /// The result is always safe for slicing using the `values[start..][0..count]` idiom,
299: /// even when no elements are matched.
300: pub inline fn binary_search_values_range(
301:     comptime Key: type,
302:     comptime Value: type,
303:     comptime key_from_value: fn (*const Value) callconv(.@"inline") Key,
304:     values: []const Value,
305:     key_min: Key,
306:     key_max: Key,
307: ) BinarySearchRange {
308:     const upsert_indexes = binary_search_values_range_upsert_indexes(
309:         Key,
310:         Value,
311:         key_from_value,
312:         values,
313:         key_min,
314:         key_max,
315:     );
316: 
317:     if (upsert_indexes.start == values.len) return .{
318:         .start = upsert_indexes.start -| 1,
319:         .count = 0,
320:     };
321: 
322:     const inclusive = @intFromBool(
323:         upsert_indexes.end < values.len and
324:             key_max == key_from_value(&values[upsert_indexes.end]),
325:     );
326:     return .{
327:         .start = upsert_indexes.start,
328:         .count = upsert_indexes.end - upsert_indexes.start + inclusive,
329:     };
330: }
331: 
332: pub inline fn binary_search_keys_range(
333:     comptime Key: type,
334:     keys: []const Key,
335:     key_min: Key,
336:     key_max: Key,
337: ) BinarySearchRange {
338:     return binary_search_values_range(
339:         Key,
340:         Key,
341:         struct {
342:             inline fn key_from_key(k: *const Key) Key {
343:                 return k.*;
344:             }
345:         }.key_from_key,
346:         keys,
347:         key_min,
348:         key_max,
349:     );
350: }
