373:                 switch (std.math.order(key, target_key)) {
374:                     .lt => expect.index = @intCast(i + 1),
375:                     .eq => {
376:                         expect.index = @intCast(i);
377:                         expect.exact = true;
378:                         if (mode == .lower_bound) break;
379:                     },
380:                     .gt => break,
381:                 }
382:             }
