14: /// A "segmented array" is an array with efficient (amortized) random-insert/remove operations.
15: /// Also known as an "unrolled linked list": https://en.wikipedia.org/wiki/Unrolled_linked_list
16: ///
17: /// The structure consists of an array list of "nodes". Each node is a non-empty array of T.
18: /// When a node fills, it is split into two adjacent, partially-full nodes.
19: /// When a node empties, it is joined with a nearby node.
20: ///
21: /// An absolute index is offset from the start of the segmented array.
22: /// A relative index is offset from the start of a node.
23: pub fn SegmentedArrayType(
24:     comptime T: type,
25:     comptime NodePool: type,
26:     comptime element_count_max: u32,
27:     comptime options: Options,
28: ) type {
29:     return SegmentedArrayBaseType(T, NodePool, element_count_max, null, {}, options);
30: }
31: 
32: pub fn SortedSegmentedArrayType(
33:     comptime T: type,
34:     comptime NodePool: type,
35:     comptime element_count_max: u32,
36:     comptime Key: type,
37:     comptime key_from_value: fn (*const T) callconv(.@"inline") Key,
38:     comptime options: Options,
39: ) type {
40:     return SegmentedArrayBaseType(T, NodePool, element_count_max, Key, key_from_value, options);
41: }
42: 
43: pub const Options = struct {
44:     /// Assert all invariants before/after every public function.
45:     /// Very expensive - only enable for debugging/fuzzing.
46:     verify: bool = false,
47: };
48: 
49: fn SegmentedArrayBaseType(
50:     comptime T: type,
51:     comptime NodePool: type,
52:     comptime element_count_max: u32,
53:     // Set when the SegmentedArray is ordered:
54:     comptime Key: ?type,
55:     comptime key_from_value: if (Key) |K| (fn (*const T) callconv(.@"inline") K) else void,
56:     comptime options: Options,
57: ) type {
58:     comptime assert(Key == null or @typeInfo(Key.?) == .int or @typeInfo(Key.?) == .comptime_int);
59: 
60:     return struct {
61:         const SegmentedArray = @This();
62: 
63:         pub const Cursor = struct {
64:             node: u32,
65:             relative_index: u32,
66:         };
67: 
68:         // We can't use @divExact() here as we store TableInfo structs of various sizes in this
69:         // data structure. This means that there may be padding at the end of the node.
70:         pub const node_capacity = blk: {
71:             const max = @divFloor(NodePool.node_size, @sizeOf(T));
72: 
73:             // We require that the node capacity is evenly divisible by 2 to simplify our code
74:             // that splits/joins nodes at the midpoint.
75:             const capacity = if (max % 2 == 0) max else max - 1;
76: 
77:             assert(capacity >= 2);
78:             assert(capacity % 2 == 0);
79:             break :blk capacity;
80:         };
81: 
82:         comptime {
83:             // If this assert fails, we should be using a non-segmented array instead!
84:             assert(element_count_max > node_capacity);
85: 
86:             // We use u32 for indexes and counts.
87:             assert(element_count_max <= std.math.maxInt(u32));
88: 
89:             // The buffers returned from the node_pool must be able to store T with correct
90:             // alignment.
91:             assert(NodePool.node_alignment >= @alignOf(T));
92:         }
93: 
94:         pub const node_count_max_naive = blk: {
95:             // If a node fills up it is divided into two new nodes. Therefore,
96:             // the worst possible space overhead is when all nodes are half full.
97:             // This uses flooring division, we want to examine the worst case here.
98:             const elements_per_node_min = @divExact(node_capacity, 2);
99:             break :blk div_ceil(element_count_max, elements_per_node_min);
100:         };
101: 
102:         // We can't always actually reach node_count_max_naive in all configurations.
103:         // If we're at node_count_max_naive-1 nodes, in order to split one more node we need:
104:         pub const node_count_max = if (element_count_max >=
105:             // * The node that we split must be full.
106:             node_capacity +
107:                 // * The last node must have at least one element.
108:                 1 +
109:                 // * All other nodes must be at least half-full.
110:                 ((node_count_max_naive -| 3) * @divExact(node_capacity, 2)) +
111:                 // * And then we insert one more element into the full node.
112:                 1)
113:             node_count_max_naive
114:         else
115:             node_count_max_naive - 1;
116: 
117:         node_count: u32 = 0,
118:         /// This is the segmented array. The first node_count pointers are non-null.
119:         /// The rest are null. We only use optional pointers here to get safety checks.
120:         nodes: *[node_count_max]?*[node_capacity]T,
121:         /// Since nodes in a segmented array are usually not full, computing the absolute index
122:         /// of an element in the full array is O(N) over the number of nodes. To avoid this cost
123:         /// we precompute the absolute index of the first element of each node.
124:         /// To avoid a separate counts field, we derive the number of elements in a node from the
125:         /// index of that node and the next node.
126:         /// To avoid special casing the count() function for the last node, we increase the array
127:         /// length by 1 and store the total element count in the last slot.
128:         indexes: *[node_count_max + 1]u32,
129: 
130:         pub fn init(allocator: mem.Allocator) !SegmentedArray {
131:             const nodes = try allocator.create([node_count_max]?*[node_capacity]T);
132:             errdefer allocator.destroy(nodes);
133: 
134:             const indexes = try allocator.create([node_count_max + 1]u32);
135:             errdefer allocator.destroy(indexes);
136: 
137:             @memset(nodes, null);
138:             indexes[0] = 0;
139: 
140:             const array = SegmentedArray{
141:                 .nodes = nodes,
142:                 .indexes = indexes,
143:             };
144: 
145:             if (options.verify) array.verify();
146: 
147:             return array;
148:         }
149: 
150:         pub fn deinit(array: SegmentedArray, allocator: mem.Allocator, node_pool: *NodePool) void {
151:             if (options.verify) array.verify();
152: 
153:             for (array.nodes[0..array.node_count]) |node| {
154:                 node_pool.release(@ptrCast(@alignCast(node.?)));
155:             }
156:             allocator.free(array.nodes);
157:             allocator.free(array.indexes);
158:         }
159: 
160:         pub fn reset(array: *SegmentedArray, node_pool: *NodePool) void {
161:             if (options.verify) array.verify();
162: 
163:             for (array.nodes[0..array.node_count]) |node| {
164:                 node_pool.release(@ptrCast(@alignCast(node.?)));
165:             }
166:             @memset(array.nodes, null);
167: 
168:             array.indexes[0] = 0;
169:             array.* = .{
170:                 .nodes = array.nodes,
171:                 .indexes = array.indexes,
172:             };
173: 
174:             if (options.verify) array.verify();
175:         }
