177:         pub fn verify(array: SegmentedArray) void {
178:             assert(array.node_count <= node_count_max);
179:             for (array.nodes, 0..) |node, node_index| {
180:                 if (node_index < array.node_count) {
181:                     // The first node_count pointers are non-null.
182:                     assert(node != null);
183:                 } else {
184:                     // The rest are non-null.
185:                     assert(node == null);
186:                 }
187:             }
188:             for (array.nodes[0..array.node_count], 0..) |_, node_index| {
189:                 const c = array.count(@intCast(node_index));
190:                 // Every node is at most full.
191:                 assert(c <= node_capacity);
192:                 // Every node is at least half-full, except the last.
193:                 if (node_index < array.node_count - 1) {
194:                     assert(c >= @divTrunc(node_capacity, 2));
195:                 }
196:             }
197:             if (Key) |K| {
198:                 // If Key is not null then the elements must be sorted by key_from_value (but not
199:                 // necessarily unique).
200:                 var key_prior_or_null: ?K = null;
201:                 for (array.nodes[0..array.node_count], 0..) |_, node_index| {
202:                     for (array.node_elements(@intCast(node_index))) |*value| {
203:                         const key = key_from_value(value);
204:                         if (key_prior_or_null) |key_prior| {
205:                             assert(key_prior <= key);
206:                         }
207:                         key_prior_or_null = key;
208:                     }
209:                 }
210:             }
211:         }
