213:         /// Returns the absolute index of the element being inserted.
214:         /// Available only when `Key != null`.
215:         pub fn insert_element(
216:             array: *SegmentedArray,
217:             node_pool: *NodePool,
218:             element: T,
219:         ) u32 {
220:             comptime assert(Key != null);
221:             if (options.verify) array.verify();
222: 
223:             const count_before = array.len();
224: 
225:             const cursor = array.search(key_from_value(&element));
226:             const absolute_index = array.absolute_index_for_cursor(cursor);
227:             array.insert_elements_at_absolute_index(node_pool, absolute_index, &[_]T{element});
228: 
229:             if (options.verify) array.verify();
230: 
231:             const count_after = array.len();
232:             assert(count_after == count_before + 1);
233: 
234:             return absolute_index;
235:         }
