237:         /// Available only when `Key == null`.
238:         pub fn insert_elements(
239:             array: *SegmentedArray,
240:             node_pool: *NodePool,
241:             absolute_index: u32,
242:             elements: []const T,
243:         ) void {
244:             comptime assert(Key == null);
245:             if (options.verify) array.verify();
246: 
247:             const count_before = array.len();
248:             array.insert_elements_at_absolute_index(
249:                 node_pool,
250:                 absolute_index,
251:                 elements,
252:             );
253: 
254:             const count_after = array.len();
255:             assert(count_after == count_before + elements.len);
256: 
257:             if (options.verify) array.verify();
258:         }
