260:         fn insert_elements_at_absolute_index(
261:             array: *SegmentedArray,
262:             node_pool: *NodePool,
263:             absolute_index: u32,
264:             elements: []const T,
265:         ) void {
266:             assert(elements.len > 0);
267:             assert(absolute_index + elements.len <= element_count_max);
268: 
269:             var i: u32 = 0;
270:             while (i < elements.len) {
271:                 const batch = @min(node_capacity, elements.len - i);
272:                 array.insert_elements_batch(
273:                     node_pool,
274:                     absolute_index + i,
275:                     elements[i..][0..batch],
276:                 );
277:                 i += batch;
278:             }
279:             assert(i == elements.len);
280:         }
281: 
282:         fn insert_elements_batch(
283:             array: *SegmentedArray,
284:             node_pool: *NodePool,
285:             absolute_index: u32,
286:             elements: []const T,
287:         ) void {
288:             assert(elements.len > 0);
289:             assert(elements.len <= node_capacity);
290:             assert(absolute_index + elements.len <= element_count_max);
291: 
292:             if (array.node_count == 0) {
293:                 assert(absolute_index == 0);
294: 
295:                 array.insert_empty_node_at(node_pool, 0);
296: 
297:                 assert(array.node_count == 1);
298:                 assert(array.nodes[0] != null);
299:                 assert(array.indexes[0] == 0);
300:                 assert(array.indexes[1] == 0);
301:             }
302: 
303:             const cursor = array.cursor_for_absolute_index(absolute_index);
304:             assert(cursor.node < array.node_count);
305: 
306:             const a = cursor.node;
307:             const a_pointer = array.nodes[a].?;
308:             assert(cursor.relative_index <= array.count(a));
309: 
310:             const total = array.count(a) + @as(u32, @intCast(elements.len));
311:             if (total <= node_capacity) {
312:                 stdx.copy_right(
313:                     .inexact,
314:                     T,
315:                     a_pointer[cursor.relative_index + elements.len ..],
316:                     a_pointer[cursor.relative_index..array.count(a)],
317:                 );
318:                 stdx.copy_disjoint(.inexact, T, a_pointer[cursor.relative_index..], elements);
319: 
320:                 array.increment_indexes_after(a, @intCast(elements.len));
321:                 return;
322:             }
323: 
324:             // Insert a new node after the node being split.
325:             const b = a + 1;
326:             array.insert_empty_node_at(node_pool, b);
327:             const b_pointer = array.nodes[b].?;
328: 
329:             const a_half = div_ceil(total, 2);
330:             const b_half = total - a_half;
331:             assert(a_half >= b_half);
332:             assert(a_half + b_half == total);
333: 
334:             // The 1st case can be seen as a special case of the 2nd.
335:             // The 5th case can be seen as a special case of the 4th.
336:             //
337:             // elements: [yyyyyy], relative_index: 0
338:             // [xxxxx_][______]
339:             // [______][xxxxx_] // after first copy_backwards
340:             // [______][xxxxx_] // skip mem.copyBackwards (a_half >= relative_index)
341:             // [yyyyyy][xxxxx_] // after second copy_backwards
342:             //
343:             // elements: [yy], relative_index: 1
344:             // [xxxxx_][______]
345:             // [x__x__][xxx___] // after first copy_backwards
346:             // [x__x__][xxx___] // skip mem.copyBackwards (a_half >= relative_index)
347:             // [xyyx__][xxx___] // after second copy_backwards
348:             //
349:             // elements: [yy], relative_index: 2
350:             // [xxx_][____]
351:             // [xx__][_x__] // after first copy_backwards
352:             // [xx__][_x__] // skip mem.copyBackwards (a_half >= relative_index)
353:             // [xxy_][yx__] // after second copy_backwards
354:             //
355:             // elements: [yy], relative_index: 5
356:             // [xxxxxx][______]
357:             // [xxxxx_][___x__] // after first copy_backwards
358:             // [xxxx__][x__x__] // after mem.copyBackwards (a_half < relative_index)
359:             // [xxxx__][xyyx__] // after second copy_backwards
360:             //
361:             // elements: [yyyyy_], relative_index: 5
362:             // [xxxxx_][______]
363:             // [xxxxx_][______] // after first copy_backwards
364:             // [xxxxx_][______] // skip mem.copyBackwards (a_half >= relative_index)
365:             // [xxxxx_][yyyyy_] // after second copy_backwards
366: 
367:             const a_half_pointer = a_pointer[0..a_half];
368:             const b_half_pointer = b_pointer[0..b_half];
369: 
370:             // Move part of `a` forwards to make space for elements.
371:             copy_backwards(
372:                 a_half_pointer,
373:                 b_half_pointer,
374:                 cursor.relative_index + elements.len,
375:                 a_pointer[cursor.relative_index..array.count(a)],
376:             );
377: 
378:             if (a_half < cursor.relative_index) {
379:                 // Move the part of `a` that is past the half-way point into `b`.
380:                 stdx.copy_right(
381:                     .inexact,
382:                     T,
383:                     b_half_pointer,
384:                     a_pointer[a_half..cursor.relative_index],
385:                 );
386:             }
387: 
388:             // Move `elements` into `a` and/or `b`.
389:             copy_backwards(
390:                 a_half_pointer,
391:                 b_half_pointer,
392:                 cursor.relative_index,
393:                 elements,
394:             );
395: 
396:             array.indexes[b] = array.indexes[a] + a_half;
397:             array.increment_indexes_after(b, @intCast(elements.len));
398:         }
399: 
400:         /// Behaves like mem.copyBackwards, but as if `a` and `b` were a single contiguous slice.
401:         /// `target` is the destination index within the concatenation of `a` and `b`.
402:         fn copy_backwards(
403:             a: []T,
404:             b: []T,
405:             target: usize,
406:             source: []const T,
407:         ) void {
408:             assert(target + source.len <= a.len + b.len);
409:             const target_a = a[@min(target, a.len)..@min(target + source.len, a.len)];
410:             const target_b = b[target -| a.len..(target + source.len) -| a.len];
411:             assert(target_a.len + target_b.len == source.len);
412:             const source_a = source[0..target_a.len];
413:             const source_b = source[target_a.len..];
414:             if (target_b.ptr != source_b.ptr) {
415:                 stdx.copy_right(.exact, T, target_b, source_b);
416:             }
417:             if (target_a.ptr != source_a.ptr) {
418:                 stdx.copy_right(.exact, T, target_a, source_a);
419:             }
420:         }
