422:         /// Insert an empty node at index `node`.
423:         fn insert_empty_node_at(array: *SegmentedArray, node_pool: *NodePool, node: u32) void {
424:             assert(node <= array.node_count);
425:             assert(array.node_count + 1 <= node_count_max);
426: 
427:             stdx.copy_right(
428:                 .exact,
429:                 ?*[node_capacity]T,
430:                 array.nodes[node + 1 .. array.node_count + 1],
431:                 array.nodes[node..array.node_count],
432:             );
433:             stdx.copy_right(
434:                 .exact,
435:                 u32,
436:                 array.indexes[node + 1 .. array.node_count + 2],
437:                 array.indexes[node .. array.node_count + 1],
438:             );
439: 
440:             array.node_count += 1;
441:             const node_pointer = node_pool.acquire();
442:             comptime {
443:                 // @ptrCast does not check that the size or alignment agree
444:                 assert(std.meta.alignment(@TypeOf(node_pointer)) >= @alignOf(T));
445:                 assert(@sizeOf(@TypeOf(node_pointer.*)) >= @sizeOf([node_capacity]T));
446:             }
447:             array.nodes[node] = @ptrCast(@alignCast(node_pointer));
448:             assert(array.indexes[node] == array.indexes[node + 1]);
449:         }
