451:         pub fn remove_elements(
452:             array: *SegmentedArray,
453:             node_pool: *NodePool,
454:             absolute_index: u32,
455:             remove_count: u32,
456:         ) void {
457:             if (options.verify) array.verify();
458: 
459:             assert(array.node_count > 0);
460:             assert(remove_count > 0);
461:             assert(absolute_index + remove_count <= element_count_max);
462:             assert(absolute_index + remove_count <= array.indexes[array.node_count]);
463: 
464:             const half = @divExact(node_capacity, 2);
465: 
466:             var i: u32 = remove_count;
467:             while (i > 0) {
468:                 const batch = @min(half, i);
469:                 array.remove_elements_batch(node_pool, absolute_index, batch);
470:                 i -= batch;
471:             }
472: 
473:             if (options.verify) array.verify();
474:         }
475: 
476:         fn remove_elements_batch(
477:             array: *SegmentedArray,
478:             node_pool: *NodePool,
479:             absolute_index: u32,
480:             remove_count: u32,
481:         ) void {
482:             assert(array.node_count > 0);
483: 
484:             // Restricting the batch size to half node capacity ensures that elements
485:             // are removed from at most two nodes.
486:             const half = @divExact(node_capacity, 2);
487:             assert(remove_count <= half);
488:             assert(remove_count > 0);
489: 
490:             assert(absolute_index + remove_count <= element_count_max);
491:             assert(absolute_index + remove_count <= array.indexes[array.node_count]);
492: 
493:             const cursor = array.cursor_for_absolute_index(absolute_index);
494:             assert(cursor.node < array.node_count);
495: 
496:             const a = cursor.node;
497:             const a_pointer = array.nodes[a].?;
498:             const a_remaining = cursor.relative_index;
499: 
500:             // Remove elements from exactly one node:
501:             if (a_remaining + remove_count <= array.count(a)) {
502:                 stdx.copy_left(
503:                     .inexact,
504:                     T,
505:                     a_pointer[a_remaining..],
506:                     a_pointer[a_remaining + remove_count .. array.count(a)],
507:                 );
508: 
509:                 array.decrement_indexes_after(a, remove_count);
510: 
511:                 array.maybe_remove_or_merge_node_with_next(node_pool, a);
512:                 return;
513:             }
514: 
515:             // Remove elements from exactly two nodes:
516: 
517:             const b = a + 1;
518:             const b_pointer = array.nodes[b].?;
519:             const b_remaining = b_pointer[remove_count -
520:                 (array.count(a) - a_remaining) .. array.count(b)];
521: 
522:             assert(@intFromPtr(b_remaining.ptr) > @intFromPtr(b_pointer));
523: 
524:             // Only one of these nodes may become empty, as we limit batch size to
525:             // half node capacity.
526:             assert(a_remaining > 0 or b_remaining.len > 0);
527: 
528:             if (a_remaining >= half) {
529:                 stdx.copy_left(.inexact, T, b_pointer, b_remaining);
530: 
531:                 array.indexes[b] = array.indexes[a] + a_remaining;
532:                 array.decrement_indexes_after(b, remove_count);
533: 
534:                 array.maybe_remove_or_merge_node_with_next(node_pool, b);
535:             } else if (b_remaining.len >= half) {
536:                 assert(a_remaining < half);
537: 
538:                 array.indexes[b] = array.indexes[a] + a_remaining;
539:                 array.decrement_indexes_after(b, remove_count);
540: 
541:                 array.maybe_merge_nodes(node_pool, a, b_remaining);
542:             } else {
543:                 assert(a_remaining < half and b_remaining.len < half);
544:                 assert(a_remaining + b_remaining.len <= node_capacity);
545: 
546:                 stdx.copy_disjoint(.inexact, T, a_pointer[a_remaining..], b_remaining);
547: 
548:                 array.indexes[b] =
549:                     array.indexes[a] + a_remaining + @as(u32, @intCast(b_remaining.len));
550:                 array.decrement_indexes_after(b, remove_count);
551: 
552:                 array.remove_empty_node_at(node_pool, b);
553: 
554:                 // Either:
555:                 // * `b` was the last node so now `a` is the last node
556:                 // * both `a` and `b` were at least half-full so now `a` is at least half-full
557:                 assert(b == array.node_count or array.count(a) >= half);
558:             }
559:         }
560: 
561:         fn maybe_remove_or_merge_node_with_next(
562:             array: *SegmentedArray,
563:             node_pool: *NodePool,
564:             node: u32,
565:         ) void {
566:             assert(node < array.node_count);
567: 
568:             if (array.count(node) == 0) {
569:                 array.remove_empty_node_at(node_pool, node);
570:                 return;
571:             }
572: 
573:             if (node == array.node_count - 1) return;
574: 
575:             const next_elements = array.nodes[node + 1].?[0..array.count(node + 1)];
576:             array.maybe_merge_nodes(node_pool, node, next_elements);
577:         }
578: 
579:         fn maybe_merge_nodes(
580:             array: *SegmentedArray,
581:             node_pool: *NodePool,
582:             node: u32,
583:             elements_next_node: []T,
584:         ) void {
585:             const half = @divExact(node_capacity, 2);
586: 
587:             const a = node;
588:             const a_pointer = array.nodes[a].?;
589:             assert(array.count(a) <= node_capacity);
590: 
591:             // The elements_next_node slice may not be at the start of the node,
592:             // but the length of the slice will match count(b).
593:             const b = a + 1;
594:             const b_pointer = array.nodes[b].?;
595:             const b_elements = elements_next_node;
596:             assert(b_elements.len == array.count(b));
597:             assert(b_elements.len > 0);
598:             assert(b_elements.len >= half or b == array.node_count - 1);
599:             assert(b_elements.len <= node_capacity);
600:             assert(@intFromPtr(b_elements.ptr) >= @intFromPtr(b_pointer));
601: 
602:             // Our function would still be correct if this assert fails, but we would
603:             // unnecessarily copy all elements of b to node a and then delete b
604:             // instead of simply deleting a.
605:             assert(!(array.count(a) == 0 and b_pointer == b_elements.ptr));
606: 
607:             const total = array.count(a) + @as(u32, @intCast(b_elements.len));
608:             if (total <= node_capacity) {
609:                 stdx.copy_disjoint(.inexact, T, a_pointer[array.count(a)..], b_elements);
610: 
611:                 array.indexes[b] = array.indexes[b + 1];
612:                 array.remove_empty_node_at(node_pool, b);
613: 
614:                 assert(array.count(a) >= half or a == array.node_count - 1);
615:             } else if (array.count(a) < half) {
616:                 const a_half = div_ceil(total, 2);
617:                 const b_half = total - a_half;
618:                 assert(a_half >= b_half);
619:                 assert(a_half + b_half == total);
620: 
621:                 stdx.copy_disjoint(
622:                     .exact,
623:                     T,
624:                     a_pointer[array.count(a)..a_half],
625:                     b_elements[0 .. a_half - array.count(a)],
626:                 );
627:                 stdx.copy_left(.inexact, T, b_pointer, b_elements[a_half - array.count(a) ..]);
628: 
629:                 array.indexes[b] = array.indexes[a] + a_half;
630: 
631:                 assert(array.count(a) >= half);
632:                 assert(array.count(b) >= half);
633:             } else {
634:                 assert(b_pointer == b_elements.ptr);
635:                 assert(array.indexes[b] + b_elements.len == array.indexes[b + 1]);
636:             }
637:         }
638: 
639:         /// Remove an empty node at index `node`.
640:         fn remove_empty_node_at(array: *SegmentedArray, node_pool: *NodePool, node: u32) void {
641:             assert(array.node_count > 0);
642:             assert(node < array.node_count);
643:             assert(array.count(node) == 0);
644: 
645:             node_pool.release(@ptrCast(@alignCast(array.nodes[node].?)));
646: 
647:             stdx.copy_left(
648:                 .exact,
649:                 ?*[node_capacity]T,
650:                 array.nodes[node .. array.node_count - 1],
651:                 array.nodes[node + 1 .. array.node_count],
652:             );
653:             stdx.copy_left(
654:                 .exact,
655:                 u32,
656:                 array.indexes[node..array.node_count],
657:                 array.indexes[node + 1 .. array.node_count + 1],
658:             );
659: 
660:             array.node_count -= 1;
661:             array.nodes[array.node_count] = null;
662:             array.indexes[array.node_count + 1] = undefined;
663:         }
664: 
665:         inline fn count(array: SegmentedArray, node: u32) u32 {
666:             const result = array.indexes[node + 1] - array.indexes[node];
667:             assert(result <= node_capacity);
668:             return result;
669:         }
670: 
671:         inline fn increment_indexes_after(array: *SegmentedArray, node: u32, delta: u32) void {
672:             for (array.indexes[node + 1 .. array.node_count + 1]) |*i| i.* += delta;
673:         }
674: 
675:         inline fn decrement_indexes_after(array: *SegmentedArray, node: u32, delta: u32) void {
676:             for (array.indexes[node + 1 .. array.node_count + 1]) |*i| i.* -= delta;
677:         }
678: 
679:         pub inline fn node_elements(array: SegmentedArray, node: u32) []T {
680:             assert(node < array.node_count);
681:             return array.nodes[node].?[0..array.count(node)];
682:         }
683: 
684:         pub inline fn node_last_element(array: SegmentedArray, node: u32) T {
685:             return array.node_elements(node)[array.count(node) - 1];
686:         }
687: 
688:         pub inline fn element_at_cursor(array: SegmentedArray, cursor: Cursor) T {
689:             return array.node_elements(cursor.node)[cursor.relative_index];
690:         }
691: 
692:         pub inline fn first(_: SegmentedArray) Cursor {
693:             return .{
694:                 .node = 0,
695:                 .relative_index = 0,
696:             };
697:         }
698: 
699:         pub inline fn last(array: SegmentedArray) Cursor {
700:             if (array.node_count == 0) return array.first();
701: 
702:             return .{
703:                 .node = array.node_count - 1,
704:                 .relative_index = array.count(array.node_count - 1) - 1,
705:             };
706:         }
707: 
708:         pub inline fn len(array: SegmentedArray) u32 {
709:             const result = array.indexes[array.node_count];
710:             assert(result <= element_count_max);
711:             return result;
712:         }
713: 
714:         // TODO Consider enabling ReleaseFast for this once tested.
715:         pub fn absolute_index_for_cursor(array: SegmentedArray, cursor: Cursor) u32 {
716:             if (array.node_count == 0) {
717:                 assert(cursor.node == 0);
718:                 assert(cursor.relative_index == 0);
719:                 return 0;
720:             }
721:             assert(cursor.node < array.node_count);
722:             if (cursor.node == array.node_count - 1) {
723:                 // Insertion may target the index one past the end of the array.
724:                 assert(cursor.relative_index <= array.count(cursor.node));
725:             } else {
726:                 assert(cursor.relative_index < array.count(cursor.node));
727:             }
728:             return array.indexes[cursor.node] + cursor.relative_index;
729:         }
730: 
731:         fn cursor_for_absolute_index(array: SegmentedArray, absolute_index: u32) Cursor {
732:             // This function could handle node_count == 0 by returning a zero Cursor.
733:             // However, this is an internal function and we don't require this behavior.
734:             assert(array.node_count > 0);
735: 
736:             assert(absolute_index < element_count_max);
737:             assert(absolute_index <= array.len());
738: 
739:             const result = binary_search_keys(
740:                 u32,
741:                 array.indexes[0..array.node_count],
742:                 absolute_index,
743:                 .{},
744:             );
745: 
746:             if (result.exact) {
747:                 return .{
748:                     .node = result.index,
749:                     .relative_index = 0,
750:                 };
751:             } else {
752:                 const node = result.index - 1;
753:                 const relative_index = absolute_index - array.indexes[node];
754:                 if (node == array.node_count - 1) {
755:                     // Insertion may target the index one past the end of the array.
756:                     assert(relative_index <= array.count(node));
757:                 } else {
758:                     assert(relative_index < array.count(node));
759:                 }
760:                 return .{
761:                     .node = node,
762:                     .relative_index = relative_index,
763:                 };
764:             }
765:         }
