767:         pub const Iterator = struct {
768:             array: *const SegmentedArray,
769:             direction: Direction,
770: 
771:             cursor: Cursor,
772: 
773:             /// The user may set this early to stop iteration. For example,
774:             /// if the returned table info is outside the key range.
775:             done: bool = false,
776: 
777:             pub fn next(it: *Iterator) ?*T {
778:                 if (it.done) return null;
779: 
780:                 assert(it.cursor.node < it.array.node_count);
781: 
782:                 const elements = it.array.node_elements(it.cursor.node);
783:                 const element = &elements[it.cursor.relative_index];
784: 
785:                 switch (it.direction) {
786:                     .ascending => {
787:                         if (it.cursor.relative_index == elements.len - 1) {
788:                             if (it.cursor.node == it.array.node_count - 1) {
789:                                 it.done = true;
790:                             } else {
791:                                 it.cursor.node += 1;
792:                                 it.cursor.relative_index = 0;
793:                             }
794:                         } else {
795:                             it.cursor.relative_index += 1;
796:                         }
797:                     },
798:                     .descending => {
799:                         if (it.cursor.relative_index == 0) {
800:                             if (it.cursor.node == 0) {
801:                                 it.done = true;
802:                             } else {
803:                                 it.cursor.node -= 1;
804:                                 it.cursor.relative_index = it.array.count(it.cursor.node) - 1;
805:                             }
806:                         } else {
807:                             it.cursor.relative_index -= 1;
808:                         }
809:                     },
810:                 }
811: 
812:                 return element;
813:             }
814:         };
