816:         pub fn iterator_from_cursor(
817:             array: *const SegmentedArray,
818:             /// First element of iteration.
819:             cursor: Cursor,
820:             direction: Direction,
821:         ) Iterator {
822:             if (array.node_count == 0) {
823:                 assert(cursor.node == 0);
824:                 assert(cursor.relative_index == 0);
825: 
826:                 return .{
827:                     .array = array,
828:                     .direction = direction,
829:                     .cursor = .{ .node = 0, .relative_index = 0 },
830:                     .done = true,
831:                 };
832:             } else if (cursor.node == array.node_count - 1 and
833:                 cursor.relative_index == array.count(cursor.node))
834:             {
835:                 return switch (direction) {
836:                     .ascending => .{
837:                         .array = array,
838:                         .direction = direction,
839:                         .cursor = cursor,
840:                         .done = true,
841:                     },
842:                     .descending => .{
843:                         .array = array,
844:                         .direction = direction,
845:                         .cursor = .{
846:                             .node = cursor.node,
847:                             .relative_index = cursor.relative_index - 1,
848:                         },
849:                     },
850:                 };
851:             } else {
852:                 assert(cursor.node < array.node_count);
853:                 assert(cursor.relative_index < array.count(cursor.node));
854: 
855:                 return .{
856:                     .array = array,
857:                     .direction = direction,
858:                     .cursor = cursor,
859:                 };
860:             }
861:         }
862: 
863:         pub fn iterator_from_index(
864:             array: *const SegmentedArray,
865:             /// First element of iteration.
866:             absolute_index: u32,
867:             direction: Direction,
868:         ) Iterator {
869:             assert(absolute_index < element_count_max);
870: 
871:             if (array.node_count == 0) {
872:                 assert(absolute_index == 0);
873: 
874:                 return Iterator{
875:                     .array = array,
876:                     .direction = direction,
877:                     .cursor = .{ .node = 0, .relative_index = 0 },
878:                     .done = true,
879:                 };
880:             } else {
881:                 assert(absolute_index < array.len());
882: 
883:                 return Iterator{
884:                     .array = array,
885:                     .direction = direction,
886:                     .cursor = array.cursor_for_absolute_index(absolute_index),
887:                 };
888:             }
889:         }
