891:         /// Returns a cursor to the index of the key either exactly equal to the target key or,
892:         /// if there is no exact match, the next greatest key.
893:         /// Available only when `Key != null`.
894:         pub fn search(
895:             array: *const SegmentedArray,
896:             key: K: {
897:                 assert(Key != null);
898:                 break :K Key.?;
899:             },
900:         ) Cursor {
901:             const K = Key.?;
902:             if (array.node_count == 0) {
903:                 return .{
904:                     .node = 0,
905:                     .relative_index = 0,
906:                 };
907:             }
908: 
909:             var offset: usize = 0;
910:             var length: usize = array.node_count;
911:             while (length > 1) {
912:                 const half = length / 2;
913:                 const mid = offset + half;
914: 
915:                 const node = &array.nodes[mid].?[0];
916: 
917:                 if (key_from_value(node) < key) {
918:                     @branchHint(.unpredictable);
919:                     offset = mid;
920:                 }
921: 
922:                 length -= half;
923:             }
924: 
925:             // Unlike a normal binary search, don't increment the offset when "key" is higher
926:             // than the element — "round down" to the previous node.
927:             // This guarantees that the node result is never "== node_count".
928:             //
929:             // (If there are two adjacent nodes starting with keys A and C, and we search B,
930:             // we want to pick the A node.)
931:             const node: u32 = @intCast(offset);
932:             assert(node < array.node_count);
933: 
934:             const relative_index = binary_search_values_upsert_index(
935:                 K,
936:                 T,
937:                 key_from_value,
938:                 array.node_elements(node),
939:                 key,
940:                 .{},
941:             );
942: 
943:             // Follow the same rule as absolute_index_for_cursor:
944:             // only return relative_index==array.count() at the last node.
945:             if (node + 1 < array.node_count and
946:                 relative_index == array.count(node))
947:             {
948:                 return .{
949:                     .node = node + 1,
950:                     .relative_index = 0,
951:                 };
952:             } else {
953:                 return .{
954:                     .node = node,
955:                     .relative_index = relative_index,
956:                 };
957:             }
958:         }
959:     };
960: }
