962: test "SortedSegmentedArray duplicate elements" {
963:     // Create [0, 0, 0, 100, 100, 100, ~0, ~0, ~0] array, verify that the search is left-biased.
964:     const testing = std.testing;
965: 
966:     const NodePoolType = @import("node_pool.zig").NodePoolType;
967:     const TestPool = NodePoolType(128 * @sizeOf(u32), 2 * @alignOf(u32));
968:     const TestArray = SortedSegmentedArrayType(
969:         u32,
970:         TestPool,
971:         1024,
972:         u32,
973:         struct {
974:             inline fn key_from_value(value: *const u32) u32 {
975:                 return value.*;
976:             }
977:         }.key_from_value,
978:         .{ .verify = true },
979:     );
980: 
981:     var pool: TestPool = undefined;
982:     try pool.init(testing.allocator, TestArray.node_count_max);
983:     defer pool.deinit(testing.allocator);
984: 
985:     var array = try TestArray.init(testing.allocator);
986:     defer array.deinit(testing.allocator, &pool);
987: 
988:     for (0..3) |index| {
989:         // Elements are inserted to the left of a row of duplicates.
990:         var inserted_at = array.insert_element(&pool, 0);
991:         try testing.expectEqual(inserted_at, 0);
992: 
993:         inserted_at = array.insert_element(&pool, 100);
994:         try testing.expectEqual(inserted_at, @as(u32, @intCast(index + 1)));
995: 
996:         inserted_at = array.insert_element(&pool, math.maxInt(u32));
997:         try testing.expectEqual(inserted_at, @as(u32, @intCast((index + 1) * 2)));
998:     }
999:     try testing.expectEqual(array.len(), 9);
1000: 
1001:     // Search finds the leftmost element.
1002:     try testing.expectEqual(array.absolute_index_for_cursor(array.search(0)), 0);
1003:     try testing.expectEqual(array.absolute_index_for_cursor(array.search(100)), 3);
1004:     try testing.expectEqual(array.absolute_index_for_cursor(array.search(math.maxInt(u32))), 6);
1005: 
1006:     // Ascending iterators pick the leftmost element.
1007:     // Descending iterators are weird --- they _also_ pick the leftmost element, although the
1008:     // rightmost makes more sense.
1009:     {
1010:         const target: u32 = 0;
1011:         var it = array.iterator_from_cursor(array.search(target), .ascending);
1012:         try testing.expectEqual(it.next().?.*, 0);
1013:         try testing.expectEqual(it.next().?.*, 0);
1014:         try testing.expectEqual(it.next().?.*, 0);
1015:         try testing.expectEqual(it.next().?.*, 100);
1016: 
1017:         it = array.iterator_from_cursor(array.search(target), .descending);
1018:         try testing.expectEqual(it.next().?.*, 0);
1019:         try testing.expectEqual(it.next(), null);
1020:     }
1021: 
1022:     {
1023:         const target: u32 = 100;
1024:         var it = array.iterator_from_cursor(array.search(target), .ascending);
1025:         try testing.expectEqual(it.next().?.*, 100);
1026:         try testing.expectEqual(it.next().?.*, 100);
1027:         try testing.expectEqual(it.next().?.*, 100);
1028:         try testing.expectEqual(it.next().?.*, math.maxInt(u32));
1029: 
1030:         it = array.iterator_from_cursor(array.search(target), .descending);
1031:         try testing.expectEqual(it.next().?.*, 100);
1032:         try testing.expectEqual(it.next().?.*, 0);
1033:     }
1034: 
1035:     {
1036:         const target: u32 = math.maxInt(u32);
1037:         var it = array.iterator_from_cursor(array.search(target), .ascending);
1038:         try testing.expectEqual(it.next().?.*, math.maxInt(u32));
1039:         try testing.expectEqual(it.next().?.*, math.maxInt(u32));
1040:         try testing.expectEqual(it.next().?.*, math.maxInt(u32));
1041:         try testing.expectEqual(it.next(), null);
1042: 
1043:         it = array.iterator_from_cursor(array.search(target), .descending);
1044:         try testing.expectEqual(it.next().?.*, math.maxInt(u32));
1045:         try testing.expectEqual(it.next().?.*, 100);
