1049: /// In order to avoid making internal details of segmented array public, the fuzzing code is defined
1050: /// in this file an is driven by =segmented_array_fuzz.zig`.
1051: fn FuzzContextType(
1052:     comptime T: type,
1053:     comptime node_size: u32,
1054:     comptime element_count_max: u32,
1055:     comptime Key: type,
1056:     comptime key_from_value: fn (*const T) callconv(.@"inline") Key,
1057:     comptime element_order: enum { sorted, unsorted },
1058:     comptime options: Options,
1059: ) type {
1060:     return struct {
1061:         const FuzzContext = @This();
1062: 
1063:         const testing = std.testing;
1064:         const log = false;
1065: 
1066:         const NodePoolType = @import("node_pool.zig").NodePoolType;
1067: 
1068:         // Test overaligned nodes to catch compile errors for missing @alignCast()
1069:         const TestPool = NodePoolType(node_size, 2 * @alignOf(T));
1070:         const TestArray = switch (element_order) {
1071:             .sorted => SortedSegmentedArrayType(
1072:                 T,
1073:                 TestPool,
1074:                 element_count_max,
1075:                 Key,
1076:                 key_from_value,
1077:                 options,
1078:             ),
1079:             .unsorted => SegmentedArrayType(T, TestPool, element_count_max, options),
1080:         };
1081: 
1082:         prng: *stdx.PRNG,
1083: 
1084:         pool: TestPool,
1085:         array: TestArray,
1086: 
1087:         reference: std.ArrayList(T),
1088: 
1089:         inserts: u64 = 0,
1090:         removes: u64 = 0,
1091: 
1092:         fn init(
1093:             context: *FuzzContext,
1094:             allocator: std.mem.Allocator,
1095:             prng: *stdx.PRNG,
1096:         ) !void {
1097:             context.* = .{
1098:                 .prng = prng,
1099: 
1100:                 .pool = undefined,
1101:                 .array = undefined,
1102:                 .reference = undefined,
1103:             };
1104: 
1105:             try context.pool.init(allocator, TestArray.node_count_max);
1106:             errdefer context.pool.deinit(allocator);
1107: 
1108:             context.array = try TestArray.init(allocator);
1109:             errdefer context.array.deinit(allocator, &context.pool);
1110: 
1111:             context.reference = std.ArrayList(T).init(allocator);
1112:             errdefer context.reference.deinit();
1113:             try context.reference.ensureTotalCapacity(element_count_max);
1114:         }
1115: 
1116:         fn deinit(context: *FuzzContext, allocator: std.mem.Allocator) void {
1117:             context.array.deinit(allocator, &context.pool);
1118:             context.pool.deinit(allocator);
1119: 
1120:             context.reference.deinit();
1121:         }
1122: 
1123:         fn run(context: *FuzzContext) !void {
1124:             const Action = enum { insert, remove };
1125:             {
1126:                 var i: usize = 0;
1127:                 while (i < element_count_max * 2) : (i += 1) {
1128:                     switch (context.prng.enum_weighted(
1129:                         Action,
1130:                         .{
1131:                             .insert = 60,
1132:                             .remove = 40,
1133:                         },
1134:                     )) {
1135:                         .insert => try context.insert(),
1136:                         .remove => try context.remove(),
1137:                     }
1138:                 }
1139:             }
1140: 
1141:             {
1142:                 var i: usize = 0;
1143:                 while (i < element_count_max * 2) : (i += 1) {
1144:                     switch (context.prng.enum_weighted(
1145:                         Action,
1146:                         .{
1147:                             .insert = 40,
1148:                             .remove = 60,
1149:                         },
1150:                     )) {
1151:                         .insert => try context.insert(),
1152:                         .remove => try context.remove(),
1153:                     }
1154:                 }
1155:             }
1156: 
1157:             // Rarely, the code above won't generate an insert at all.
1158:             if (context.inserts > 0) {
1159:                 try context.remove_all();
1160:             }
1161: 
1162:             if (element_order == .unsorted) {
1163:                 // Insert at the beginning of the array until the array is full.
1164:                 while (context.array.len() < element_count_max) {
1165:                     try context.insert_before_first();
1166:                 }
1167:                 assert(context.array.node_count >= TestArray.node_count_max - 1);
1168: 
1169:                 // Remove all-but-one elements from the last node and insert them into the first
1170:                 // node.
1171:                 const element_count_last = context.array.count(context.array.node_count - 1);
1172:                 var element_index: usize = 0;
1173:                 while (element_index < element_count_last - 1) : (element_index += 1) {
1174:                     try context.remove_last();
1175:                     try context.insert_before_first();
1176:                 }
1177: 
1178:                 // We should now have maxed out our node count.
1179:                 assert(context.array.node_count == TestArray.node_count_max);
1180: 
1181:                 try context.remove_all();
1182:             }
1183:         }
1184: 
1185:         fn insert(context: *FuzzContext) !void {
1186:             const reference_len: u32 = @intCast(context.reference.items.len);
1187:             const count_free = element_count_max - reference_len;
1188: 
1189:             if (count_free == 0) return;
1190: 
1191:             var buffer: [TestArray.node_capacity * 3]T = undefined;
1192:             const count_max = @min(count_free, TestArray.node_capacity * 3);
1193:             const count = context.prng.range_inclusive(u32, 1, count_max);
1194:             context.prng.fill(mem.sliceAsBytes(buffer[0..count]));
1195: 
1196:             assert(context.reference.items.len <= element_count_max);
1197: 
1198:             switch (element_order) {
1199:                 .unsorted => {
1200:                     const index = context.prng.int_inclusive(u32, reference_len);
1201: 
1202:                     context.array.insert_elements(&context.pool, index, buffer[0..count]);
1203:                     // TODO the standard library could use an AssumeCapacity variant of this.
1204:                     context.reference.insertSlice(index, buffer[0..count]) catch unreachable;
1205:                 },
1206:                 .sorted => {
1207:                     for (buffer[0..count]) |value| {
1208:                         const index_actual = context.array.insert_element(&context.pool, value);
1209:                         const index_expect = context.reference_index(key_from_value(&value));
1210:                         context.reference.insert(index_expect, value) catch unreachable;
1211:                         try std.testing.expectEqual(index_expect, index_actual);
1212:                     }
1213:                 },
1214:             }
1215:             context.inserts += count;
1216: 
1217:             try context.verify();
1218:         }
1219: 
1220:         fn remove(context: *FuzzContext) !void {
1221:             const reference_len: u32 = @intCast(context.reference.items.len);
1222:             if (reference_len == 0) return;
1223: 
1224:             const count_max = @min(reference_len, TestArray.node_capacity * 3);
1225:             const count = context.prng.range_inclusive(u32, 1, count_max);
1226: 
1227:             assert(context.reference.items.len <= element_count_max);
1228:             const index = context.prng.int_inclusive(u32, reference_len - count);
1229: 
1230:             context.array.remove_elements(&context.pool, index, count);
1231: 
1232:             context.reference.replaceRange(index, count, &[0]T{}) catch unreachable;
1233: 
1234:             context.removes += count;
1235: 
1236:             try context.verify();
1237:         }
1238: 
1239:         fn insert_before_first(context: *FuzzContext) !void {
1240:             assert(element_order == .unsorted);
1241: 
1242:             const insert_index = context.array.absolute_index_for_cursor(context.array.first());
1243: 
1244:             var element: T = undefined;
1245:             context.prng.fill(mem.asBytes(&element));
1246: 
1247:             context.array.insert_elements(&context.pool, insert_index, &.{element});
1248:             context.reference.insert(insert_index, element) catch unreachable;
1249: 
1250:             context.inserts += 1;
1251: 
1252:             try context.verify();
1253:         }
1254: 
1255:         fn remove_last(context: *FuzzContext) !void {
1256:             assert(element_order == .unsorted);
1257: 
1258:             const remove_index = context.array.absolute_index_for_cursor(context.array.last());
1259: 
1260:             context.array.remove_elements(&context.pool, remove_index, 1);
1261:             context.reference.replaceRange(remove_index, 1, &[0]T{}) catch unreachable;
1262: 
1263:             context.removes += 1;
1264: 
1265:             try context.verify();
1266:         }
1267: 
1268:         fn remove_all(context: *FuzzContext) !void {
1269:             while (context.reference.items.len > 0) try context.remove();
1270: 
1271:             try testing.expectEqual(@as(u32, 0), context.array.len());
1272:             try testing.expect(context.inserts > 0);
1273:             try testing.expect(context.inserts == context.removes);
1274: 
1275:             if (log) {
1276:                 std.debug.print("\ninserts: {}, removes: {}\n", .{
1277:                     context.inserts,
1278:                     context.removes,
1279:                 });
1280:             }
1281: 
1282:             try context.verify();
1283:         }
1284: 
1285:         fn verify(context: *FuzzContext) !void {
1286:             if (log) {
1287:                 std.debug.print("expect: ", .{});
1288:                 for (context.reference.items) |i| std.debug.print("{}, ", .{i});
1289: 
1290:                 std.debug.print("\nactual: ", .{});
1291:                 var it = context.array.iterator_from_index(0, .ascending);
1292:                 while (it.next()) |i| std.debug.print("{}, ", .{i.*});
1293:                 std.debug.print("\n", .{});
1294:             }
1295: 
1296:             try testing.expectEqual(context.reference.items.len, context.array.len());
1297: 
1298:             {
1299:                 var it = context.array.iterator_from_index(0, .ascending);
1300: 
1301:                 for (context.reference.items) |expect| {
1302:                     const actual = it.next() orelse return error.TestUnexpectedResult;
1303:                     try testing.expectEqual(expect, actual.*);
1304:                 }
1305:                 try testing.expectEqual(@as(?*const T, null), it.next());
1306:             }
1307: 
1308:             {
1309:                 var it = context.array.iterator_from_index(
1310:                     @as(u32, @intCast(context.reference.items.len)) -| 1,
1311:                     .descending,
1312:                 );
1313: 
1314:                 var i = context.reference.items.len;
1315:                 while (i > 0) {
1316:                     i -= 1;
1317: 
1318:                     const expect = context.reference.items[i];
1319:                     const actual = it.next() orelse return error.TestUnexpectedResult;
1320:                     try testing.expectEqual(expect, actual.*);
1321:                 }
1322:                 try testing.expectEqual(@as(?*const T, null), it.next());
1323:             }
1324: 
1325:             {
1326:                 for (context.reference.items, 0..) |_, i| {
1327:                     try testing.expect(std.meta.eql(
1328:                         i,
1329:                         context.array.absolute_index_for_cursor(
1330:                             context.array.cursor_for_absolute_index(@intCast(i)),
1331:                         ),
1332:                     ));
1333:                 }
1334:             }
1335: 
1336:             if (element_order == .sorted) {
1337:                 for (context.reference.items, 0..) |*expect, i| {
1338:                     if (i == 0) continue;
1339:                     try testing.expect(key_from_value(&context.reference.items[i - 1]) <=
1340:                         key_from_value(expect));
1341:                 }
1342:             }
1343: 
1344:             if (context.array.len() == 0) {
1345:                 try testing.expectEqual(@as(u32, 0), context.array.node_count);
1346:             }
1347: 
1348:             for (context.array.nodes[context.array.node_count..]) |node| {
1349:                 try testing.expectEqual(@as(?*[TestArray.node_capacity]T, null), node);
1350:             }
1351: 
1352:             {
1353:                 var i: u32 = 0;
1354:                 while (i < context.array.node_count -| 1) : (i += 1) {
1355:                     try testing.expect(context.array.count(i) >=
1356:                         @divExact(TestArray.node_capacity, 2));
1357:                 }
1358:             }
1359:             if (element_order == .sorted) try context.verify_search();
1360:         }
