1362:         fn verify_search(context: *FuzzContext) !void {
1363:             var queries: [20]Key = undefined;
1364:             context.prng.fill(mem.sliceAsBytes(&queries));
1365: 
1366:             // Test min/max exceptional values on different SegmentedArray shapes.
1367:             queries[0] = 0;
1368:             queries[1] = math.maxInt(Key);
1369: 
1370:             for (queries) |query| {
1371:                 try testing.expectEqual(
1372:                     context.reference_index(query),
1373:                     context.array.absolute_index_for_cursor(context.array.search(query)),
1374:                 );
1375:             }
1376: 
1377:             {
1378:                 var iterator_end = context.array.iterator_from_cursor(
1379:                     context.array.search(math.maxInt(Key)),
1380:                     .ascending,
1381:                 );
1382:                 while (iterator_end.next()) |item| {
1383:                     try testing.expectEqual(key_from_value(item), math.maxInt(Key));
1384:                 }
1385:             }
1386: 
1387:             {
1388:                 // 0 is not symmetric with maxInt, because `array.search` doesn't take direction
1389:                 // into account.
1390:                 var iterator_start = context.array.iterator_from_cursor(
1391:                     context.array.search(0),
1392:                     .descending,
1393:                 );
1394:                 if (context.reference.items.len == 0) {
1395:                     try testing.expectEqual(iterator_start.next(), null);
1396:                 } else {
1397:                     try testing.expect(iterator_start.next() != null);
1398:                     try testing.expectEqual(iterator_start.next(), null);
1399:                 }
1400:             }
1401:         }
1402: 
1403:         fn reference_index(context: *const FuzzContext, key: Key) u32 {
1404:             return binary_search_values_upsert_index(
1405:                 Key,
1406:                 T,
1407:                 key_from_value,
1408:                 context.reference.items,
1409:                 key,
1410:                 .{},
1411:             );
1412:         }
1413:     };
1414: }
