1416: pub fn run_fuzz(allocator: std.mem.Allocator, seed: u64, comptime options: Options) !void {
1417:     var prng = stdx.PRNG.from_seed(seed);
1418: 
1419:     const CompositeKey = @import("composite_key.zig").CompositeKeyType(u64);
1420:     const TableType = @import("table.zig").TableType;
1421:     const TableInfoType = @import("manifest.zig").TreeTableInfoType;
1422:     const TableInfo = TableInfoType(TableType(
1423:         CompositeKey.Key,
1424:         CompositeKey,
1425:         CompositeKey.key_from_value,
1426:         CompositeKey.sentinel_key,
1427:         CompositeKey.tombstone,
1428:         CompositeKey.tombstone_from_key,
1429:         1, // Doesn't matter for this test.
1430:         .general,
1431:     ));
1432: 
1433:     const CompareInt = struct {
1434:         inline fn key_from_value(value: *const u32) u32 {
1435:             return value.*;
1436:         }
1437:     };
1438: 
1439:     const CompareTable = struct {
1440:         inline fn key_from_value(value: *const TableInfo) u64 {
1441:             return value.address;
1442:         }
1443:     };
1444: 
1445:     const TestOptions = struct {
1446:         element_type: type,
1447:         node_size: u32,
1448:         element_count_max: u32,
1449:     };
1450: 
1451:     var tested_padding = false;
1452:     var tested_node_capacity_min = false;
1453: 
1454:     // We want to explore not just the bottom boundary but also the surrounding area
1455:     // as it may also have interesting edge cases.
1456:     inline for (.{
1457:         TestOptions{ .element_type = u32, .node_size = 8, .element_count_max = 3 },
1458:         TestOptions{ .element_type = u32, .node_size = 8, .element_count_max = 4 },
1459:         TestOptions{ .element_type = u32, .node_size = 8, .element_count_max = 5 },
1460:         TestOptions{ .element_type = u32, .node_size = 8, .element_count_max = 6 },
1461:         TestOptions{ .element_type = u32, .node_size = 8, .element_count_max = 1024 },
1462:         TestOptions{ .element_type = u32, .node_size = 16, .element_count_max = 1024 },
1463:         TestOptions{ .element_type = u32, .node_size = 32, .element_count_max = 1024 },
1464:         TestOptions{ .element_type = u32, .node_size = 64, .element_count_max = 1024 },
1465:         TestOptions{ .element_type = TableInfo, .node_size = 256, .element_count_max = 3 },
1466:         TestOptions{ .element_type = TableInfo, .node_size = 256, .element_count_max = 4 },
1467:         TestOptions{ .element_type = TableInfo, .node_size = 256, .element_count_max = 1024 },
1468:         TestOptions{ .element_type = TableInfo, .node_size = 512, .element_count_max = 1024 },
1469:         TestOptions{ .element_type = TableInfo, .node_size = 1024, .element_count_max = 1024 },
1470:     }) |test_options| {
1471:         inline for (.{ .sorted, .unsorted }) |order| {
1472:             const FuzzContext = FuzzContextType(
1473:                 test_options.element_type,
1474:                 test_options.node_size,
1475:                 test_options.element_count_max,
1476:                 if (test_options.element_type == u32) u32 else u64,
1477:                 if (test_options.element_type == u32)
1478:                     CompareInt.key_from_value
1479:                 else
1480:                     CompareTable.key_from_value,
1481:                 order,
1482:                 options,
1483:             );
1484: 
1485:             var context: FuzzContext = undefined;
1486:             try context.init(allocator, &prng);
1487:             defer context.deinit(allocator);
1488: 
1489:             try context.run();
1490: 
1491:             if (test_options.node_size % @sizeOf(test_options.element_type) != 0) {
1492:                 tested_padding = true;
1493:             }
1494:             if (FuzzContext.TestArray.node_capacity == 2) tested_node_capacity_min = true;
1495:         }
1496:     }
1497: 
1498:     assert(tested_padding);
1499:     assert(tested_node_capacity_min);
1500: }
