1: //! This file implements vsr.checksum. TigerBeetle uses this checksum to:
2: //!
3: //! - detect bitrot in data on disk,
4: //! - validate network messages before casting raw bytes to an `extern struct` type,
5: //! - hash-chain prepares and client requests to have strong consistency and ordering guarantees.
6: //!
7: //! As this checksum is stored on disk, it is set in stone and impossible to change.
8: //!
9: //! We need this checksum to be fast (it's in all our hotpaths) and strong (it's our ultimate line
10: //! of defense against storage failures and some classes of software bugs).
11: //!
12: //! Our checksum of choice is based on Aegis:
13: //!
14: //! <https://datatracker.ietf.org/doc/draft-irtf-cfrg-aegis-aead/>
15: //!
16: //! We use the implementation from the Zig standard library, but here's the overall overview of the
17: //! thing works:
18: //!
19: //! - AES-block is a widely supported in hardware symmetric encryption primitive (`vaesenc`,
20: //!   `vaesdec` instructions). Hardware acceleration is what provides speed.
21: //! - Aegis is an modern Authenticated Encryption with Associated Data (AEAD) scheme based on
22: //!   AES-block.
23: //! - In AEAD, the user provides, a key, a nonce, a secret message, and associated data, and gets
24: //!   a ciphertext and an authentication tag back. Associated data is expected to be sent as plain
25: //!   text (eg, it could be routing information). The tag authenticates _both_ the secret message
26: //!   and associated data.
27: //! - AEAD can be specialized to be a MAC by using an empty secret message and zero nonce. NB:
28: //!   in mac mode, message to sign is treated as AD, not as a secret message.
29: //! - A MAC can further be specialized to be a checksum by setting the secret key to zero.
30: //!   And that's what we do here!
31: 
32: const std = @import("std");
33: const builtin = @import("builtin");
34: const mem = std.mem;
35: const testing = std.testing;
36: const assert = std.debug.assert;
37: 
38: const stdx = @import("stdx");
39: const MiB = stdx.MiB;
40: 
41: const Aegis128LMac_128 = stdx.aegis.Aegis128LMac_128;
42: 
43: var seed_once = std.once(seed_init);
44: var seed_state: Aegis128LMac_128 = undefined;
45: 
46: comptime {
47:     // As described above, TigerBeetle uses Aegis (and thus AES Blocks), for its checksumming.
48:     // While there is a software implementation, it's much slower and we don't expect to ever be
49:     // using it considering we target platforms with AES hardware acceleration.
50:     //
51:     // If you're trying to compile TigerBeetle for an older CPU without AES hardware acceleration,
52:     // you'll need to disable the following assert.
53:     assert(std.crypto.core.aes.has_hardware_support);
54: }
55: 
56: fn seed_init() void {
57:     const key: [16]u8 = @splat(0);
58:     seed_state = Aegis128LMac_128.init(&key);
59: }
60: 
61: // Lazily initialize the Aegis State instead of recomputing it on each call to checksum().
62: // Then, make a copy of the state and use that to hash the source input bytes.
63: pub fn checksum(source: []const u8) u128 {
64:     if (@inComptime()) {
65:         // Aegis128 uses hardware accelerated AES via inline asm which isn't available at comptime.
66:         // Use a hard-coded value instead and verify via a test.
67:         if (source.len == 0) return 0x49F174618255402DE6E7E3C40D60CC83;
68:     }
69:     var stream = ChecksumStream.init();
70:     stream.add(source);
71:     return stream.checksum();
72: }
73: 
74: test "checksum empty" {
75:     var stream = ChecksumStream.init();
76:     stream.add(&.{});
77:     try std.testing.expectEqual(stream.checksum(), comptime checksum(&.{}));
78: }
79: 
80: pub const ChecksumStream = struct {
81:     state: Aegis128LMac_128,
82: 
83:     pub fn init() ChecksumStream {
84:         seed_once.call();
85:         return ChecksumStream{ .state = seed_state };
86:     }
87: 
88:     pub fn add(stream: *ChecksumStream, bytes: []const u8) void {
89:         stream.state.update(bytes);
90:     }
91: 
92:     pub fn checksum(stream: *ChecksumStream) u128 {
93:         var result: u128 = undefined;
94:         stream.state.final(mem.asBytes(&result));
95:         stream.* = undefined;
96:         return result;
97:     }
98: };
99: 
100: // Note: these test vectors are not independent --- there are test vectors in AEAD papers, but they
101: // don't zero all of (nonce, key, secret message). However, the as underlying AEAD implementation
102: // matches those test vectors, the entries here are correct.
103: //
104: // They can be used to smoke-test independent implementations of TigerBeetle checksum.
105: //
106: // "checksum stability" test further nails down the exact behavior.
107: test "checksum test vectors" {
108:     const TestVector = struct {
109:         source: []const u8,
110:         hash: u128,
111:     };
112: 
113:     for (&[_]TestVector{
114:         .{
115:             .source = &[_]u8{0x00} ** 16,
116:             .hash = @byteSwap(@as(u128, 0xf72ad48dd05dd1656133101cd4be3a26)),
117:         },
118:         .{
119:             .source = &[_]u8{},
120:             .hash = @byteSwap(@as(u128, 0x83cc600dc4e3e7e62d4055826174f149)),
121:         },
122:     }) |test_vector| {
123:         try testing.expectEqual(test_vector.hash, checksum(test_vector.source));
124:     }
125: }
126: 
127: test "checksum simple fuzzing" {
128:     var prng = stdx.PRNG.from_seed(42);
129: 
130:     const msg_min = 1;
131:     const msg_max = 1 * MiB;
132: 
133:     var msg_buf = try testing.allocator.alloc(u8, msg_max);
134:     defer testing.allocator.free(msg_buf);
135: 
136:     const cipher_buf = try testing.allocator.alloc(u8, msg_max);
137:     defer testing.allocator.free(cipher_buf);
138: 
139:     var i: usize = 0;
140:     while (i < 1_000) : (i += 1) {
141:         const msg_len = prng.range_inclusive(usize, msg_min, msg_max);
142:         const msg = msg_buf[0..msg_len];
143:         prng.fill(msg);
144: 
145:         const msg_checksum = checksum(msg);
146: 
147:         // Sanity check that it's a pure function.
148:         const msg_checksum_again = checksum(msg);
149:         try testing.expectEqual(msg_checksum, msg_checksum_again);
150: 
151:         // Change the message and make sure the checksum changes.
152:         msg[prng.index(msg)] +%= 1;
153:         const changed_checksum = checksum(msg);
154:         try testing.expect(changed_checksum != msg_checksum);
155:     }
156: }
157: 
158: // Change detector test to ensure we don't inadvertency modify our checksum function.
159: test "checksum stability" {
160:     var buf: [1024]u8 = undefined;
161:     var cases: [896]u128 = undefined;
162:     var case_index: usize = 0;
163: 
164:     // Zeros of various lengths.
165:     var subcase: usize = 0;
166:     while (subcase < 128) : (subcase += 1) {
167:         const message = buf[0..subcase];
168:         @memset(message, 0);
169: 
170:         cases[case_index] = checksum(message);
171:         case_index += 1;
172:     }
173: 
174:     // 64 bytes with exactly one bit set.
175:     subcase = 0;
176:     while (subcase < 64 * 8) : (subcase += 1) {
177:         const message = buf[0..64];
178:         @memset(message, 0);
179:         message[@divFloor(subcase, 8)] = @shlExact(@as(u8, 1), @as(u3, @intCast(subcase % 8)));
180: 
181:         cases[case_index] = checksum(message);
182:         case_index += 1;
183:     }
184: 
185:     // Pseudo-random data from a specific PRNG of various lengths.
186:     var prng = stdx.PRNG.from_seed(92);
187:     subcase = 0;
188:     while (subcase < 256) : (subcase += 1) {
189:         const message = buf[0 .. subcase + 13];
190:         prng.fill(message);
191: 
192:         cases[case_index] = checksum(message);
193:         case_index += 1;
194:     }
195: 
196:     // Sanity check that we are not getting trivial answers.
197:     for (cases, 0..) |case_a, i| {
198:         assert(case_a != 0);
199:         assert(case_a != std.math.maxInt(u128));
200:         for (cases[0..i]) |case_b| assert(case_a != case_b);
201:     }
202: 
203:     // Hash me, baby, one more time! If this final hash changes, we broke compatibility in a major
204:     // way.
205:     comptime assert(builtin.target.cpu.arch.endian() == .little);
206:     const hash = checksum(mem.sliceAsBytes(&cases));
207:     try testing.expectEqual(hash, 0x82dcaacf4875b279446825b6830d1263);
208: }
