1: const std = @import("std");
2: const assert = std.debug.assert;
3: 
4: /// Marzullo's algorithm, invented by Keith Marzullo for his Ph.D. dissertation in 1984, is an
5: /// agreement algorithm used to select sources for estimating accurate time from a number of noisy
6: /// time sources. NTP uses a modified form of this called the Intersection algorithm, which returns
7: /// a larger interval for further statistical sampling. However, here we want the smallest interval.
8: pub const Marzullo = struct {
9:     /// The smallest interval consistent with the largest number of sources.
10:     pub const Interval = struct {
11:         /// The lower bound on the minimum clock offset.
12:         lower_bound: i64,
13: 
14:         /// The upper bound on the maximum clock offset.
15:         upper_bound: i64,
16: 
17:         /// The number of "truechimers" consistent with the largest number of sources.
18:         sources_true: u8,
19: 
20:         /// The number of "falsetickers" falling outside this interval.
21:         /// Where `sources_false` plus `sources_true` always equals the total number of sources.
22:         sources_false: u8,
23:     };
24: 
25:     /// A tuple represents either the lower or upper end of a bound, and is fed as input to the
26:     /// Marzullo algorithm to compute the smallest interval across all tuples.
27:     /// For example, given a clock offset to a remote replica of 3s, a round trip time of 1s, and
28:     /// a maximum tolerance between clocks of 100ms on either side, we might create two tuples, the
29:     /// lower bound having an offset of 2.4s and the upper bound having an offset of 3.6s,
30:     /// to represent the error introduced by the round trip time and by the clocks themselves.
31:     pub const Tuple = struct {
32:         /// An identifier, the index of the clock source in the list of clock sources:
33:         source: u8,
34:         offset: i64,
35:         bound: enum {
36:             lower,
37:             upper,
38:         },
39:     };
40: 
41:     /// Returns the smallest interval consistent with the largest number of sources.
42:     pub fn smallest_interval(tuples: []Tuple) Interval {
43:         // There are two bounds (lower and upper) per source clock offset sample.
44:         const sources: u8 = @intCast(@divExact(tuples.len, 2));
45: 
46:         if (sources == 0) {
47:             return Interval{
48:                 .lower_bound = 0,
49:                 .upper_bound = 0,
50:                 .sources_true = 0,
51:                 .sources_false = 0,
52:             };
53:         }
54: 
55:         // Use a simpler sort implementation than the complexity of `std.mem.sort()` for safety:
56:         std.sort.insertion(Tuple, tuples, {}, less_than);
57: 
58:         // Here is a description of the algorithm:
59:         // https://en.wikipedia.org/wiki/Marzullo%27s_algorithm#Method
60:         var best: i64 = 0;
61:         var count: i64 = 0;
62:         var previous: ?Tuple = null;
63:         var interval: Interval = undefined;
64: 
65:         for (tuples, 0..) |tuple, i| {
66:             // Verify that our sort implementation is correct:
67:             if (previous) |p| {
68:                 assert(p.offset <= tuple.offset);
69:                 if (p.offset == tuple.offset) {
70:                     if (p.bound != tuple.bound) {
71:                         assert(p.bound == .lower and tuple.bound == .upper);
72:                     } else {
73:                         assert(p.source < tuple.source);
74:                     }
75:                 }
76:             }
77:             previous = tuple;
78: 
79:             // Update the current number of overlapping intervals:
80:             switch (tuple.bound) {
81:                 .lower => count += 1,
82:                 .upper => count -= 1,
83:             }
84:             // The last upper bound tuple will have a count of one less than the lower bound.
85:             // Therefore, we should never see count >= best for the last tuple:
86:             if (count > best) {
87:                 best = count;
88:                 interval.lower_bound = tuple.offset;
89:                 interval.upper_bound = tuples[i + 1].offset;
90:             } else if (count == best and tuples[i + 1].bound == .upper) {
91:                 // This is a tie for best overlap. Both intervals have the same number of sources.
92:                 // We want to choose the smaller of the two intervals:
93:                 const alternative = tuples[i + 1].offset - tuple.offset;
94:                 if (alternative < interval.upper_bound - interval.lower_bound) {
95:                     interval.lower_bound = tuple.offset;
96:                     interval.upper_bound = tuples[i + 1].offset;
97:                 }
98:             }
99:         }
100:         assert(previous.?.bound == .upper);
101: 
102:         // The number of false sources (ones which do not overlap the optimal interval) is the
103:         // number of sources minus the value of `best`:
104:         assert(best <= sources);
105:         interval.sources_true = @intCast(best);
106:         interval.sources_false = @as(u8, @intCast(sources - @as(u8, @intCast(best))));
107:         assert(interval.sources_true + interval.sources_false == sources);
108: 
109:         return interval;
110:     }
111: 
112:     /// Sorts the list of tuples by clock offset. If two tuples with the same offset but opposite
113:     /// bounds exist, indicating that one interval ends just as another begins, then a method of
114:     /// deciding which comes first is necessary. Such an occurrence can be considered an overlap
115:     /// with no duration, which can be found by the algorithm by sorting the lower bound before the
116:     /// upper bound. Alternatively, if such pathological overlaps are considered objectionable then
117:     /// they can be avoided by sorting the upper bound before the lower bound.
118:     fn less_than(context: void, a: Tuple, b: Tuple) bool {
119:         _ = context;
120: 
121:         if (a.offset < b.offset) return true;
122:         if (b.offset < a.offset) return false;
123:         if (a.bound == .lower and b.bound == .upper) return true;
124:         if (b.bound == .lower and a.bound == .upper) return false;
125:         // Use the source index to break the tie and ensure the sort is fully specified and stable
126:         // so that different sort algorithms sort the same way:
127:         if (a.source < b.source) return true;
128:         if (b.source < a.source) return false;
129:         return false;
130:     }
131: };
132: 
133: fn test_smallest_interval(bounds: []const i64, smallest_interval: Marzullo.Interval) !void {
134:     var arena = std.heap.ArenaAllocator.init(std.heap.page_allocator);
135:     defer arena.deinit();
136: 
137:     const allocator = arena.allocator();
138: 
139:     var tuples = try allocator.alloc(Marzullo.Tuple, bounds.len);
140:     for (bounds, 0..) |bound, i| {
141:         tuples[i] = .{
142:             .source = @intCast(@divTrunc(i, 2)),
