514:     ///        (Note: This must be careful not to release while any reservations are held
515:     ///        to avoid making the reservation's acquire()s nondeterministic).
516:     pub fn release(set: *FreeSet, address: u64) void {
517:         assert(set.opened);
518: 
519:         const block = address - 1;
520:         assert(set.blocks_acquired.isSet(block));
521:         assert(!set.blocks_released.isSet(block));
522:         assert(!set.blocks_released_prior_checkpoint_durability.contains(block));
523: 
524:         // `blocks_released` remains unchanged while the current checkpoint is not durable,
525:         // since it contains blocks released in the previous checkpoint. These blocks must not be
526:         // freed till the current checkpoint is durable, so as to maintain the durability of these
527:         // blocks on a commit quorum of replicas.
528:         if (set.checkpoint_durable) {
529:             set.blocks_released.set(block);
530:         } else {
